export default "import React from 'react'\nimport {\n  AccountSelect,\n  Grid,\n  Page,\n  Container,\n  Typography,\n  Logo,\n} from '@toptal/picasso'\nimport { SPACING_8 } from '@toptal/picasso-utils'\n\nconst accounts = [\n  {\n    id: '1',\n    name: 'Phil Leif',\n    position: 'Account Owner at Stowaway Cosmetics',\n  },\n  {\n    id: '2',\n    href: '#',\n    name: 'Phil Leif',\n    position: 'Company Representative at Marketing Works',\n  },\n  {\n    id: '3',\n    href: '#',\n    name: 'Phil Leif',\n    position: 'Talent',\n    avatar: './jacqueline-with-flowers-1954-square.jpg',\n  },\n]\n\nconst Example = () => (\n  <Page>\n    <Page.Content>\n      <Grid justifyContent='center'>\n        <Grid.Item>\n          <Container flex direction='column' alignItems='center'>\n            <Logo emblem />\n            <Typography variant='heading' size='large'>\n              Select an Account\n            </Typography>\n          </Container>\n          <Container top={SPACING_8}>\n            <AccountSelect\n              accounts={accounts}\n              onSelect={account => console.log(account)}\n            />\n          </Container>\n        </Grid.Item>\n      </Grid>\n    </Page.Content>\n  </Page>\n)\n\nexport default Example\n";