export default "import React from 'react'\nimport { Dropdown, Menu, Grid } from '@toptal/picasso'\n\nconst handleClick = () => window.alert('Item clicked')\n\nconst menuItems = [\n  'Add Infraction',\n  'Convert to Sourcing Flow',\n  'Reject Application',\n  'Pause Application',\n  'Reset Application',\n  'Edit Details',\n  'Talent Profile',\n  'Communication',\n  'Request Availability',\n  'Referred Users',\n  'Deactivate Talent',\n  'Restore Talent',\n  'Convert to...',\n  'Talent Health Status',\n  'Import Contract',\n  'Workflows',\n  'Hold Payments',\n  'Remove Hold on Payments',\n  'Payments',\n  'Payment History',\n  'Download IP History',\n  'GDPR Report',\n  'GDPR Remove Data',\n  'Login as this Talent',\n  'Apply to Different Vertical',\n]\n\nconst menu = (\n  <Menu>\n    {menuItems.map((itemName, index) => (\n      <Menu.Item onClick={handleClick} key={`${itemName}${String(index)}`}>\n        {itemName}\n      </Menu.Item>\n    ))}\n  </Menu>\n)\n\nconst Example = () => (\n  <Grid direction='row'>\n    <Grid.Item>\n      <Dropdown contentOverflow='scroll' content={menu}>\n        Display the menu with a scrollbar\n        <Dropdown.Arrow />\n      </Dropdown>\n    </Grid.Item>\n    <Grid.Item>\n      <Dropdown contentOverflow='visible' content={menu}>\n        Display the menu without a scrollbar\n        <Dropdown.Arrow />\n      </Dropdown>\n    </Grid.Item>\n  </Grid>\n)\n\nexport default Example\n";