export default "import React, { useState } from 'react'\nimport {\n  QueryBuilder,\n  type RuleGroupTypeAny,\n} from '@toptal/picasso-query-builder'\nimport { Button, Container } from '@toptal/picasso'\n\nconst initialQuery: RuleGroupTypeAny = {\n  rules: [\n    {\n      field: 'name',\n      operator: '=',\n      valueSource: 'value',\n      value: 'John',\n    },\n    {\n      field: 'age',\n      operator: '=',\n      valueSource: 'value',\n      value: '21',\n    },\n  ],\n  combinator: 'and',\n}\n\nconst fields = [\n  {\n    name: 'name',\n    label: 'Name',\n    type: 'text',\n  },\n  {\n    name: 'age',\n    label: 'Age',\n    type: 'number',\n  },\n]\n\nconst Example = () => {\n  const [query, setQuery] = useState<RuleGroupTypeAny>(initialQuery)\n\n  const handleQueryChange = (newQuery: RuleGroupTypeAny) => {\n    setQuery(newQuery)\n  }\n\n  return (\n    <QueryBuilder\n      fields={fields}\n      query={query}\n      onQueryChange={handleQueryChange}\n      hideControls\n      footer={\n        <Container flex justifyContent='space-between'>\n          <Button variant='secondary'>Copy url</Button>\n          <Container flex justifyContent='flex-end'>\n            <Button variant='secondary'>Clear query</Button>\n            <Button size='medium' variant='positive'>\n              Run query\n            </Button>\n          </Container>\n        </Container>\n      }\n    />\n  )\n}\n\nexport default Example\n";