export default "import React, { useState } from 'react'\nimport type { DatePickerValue } from '@toptal/picasso'\nimport { DatePicker, Form } from '@toptal/picasso'\n\nconst Example = () => {\n  const [datepickerValue, setDatepickerValue] = useState<DatePickerValue>()\n\n  return (\n    <Form>\n      <Form.Field>\n        <Form.Label>Default</Form.Label>\n        <DatePicker\n          value={datepickerValue}\n          onChange={date => {\n            setDatepickerValue(date)\n          }}\n          status='default'\n        />\n      </Form.Field>\n      <Form.Field>\n        <Form.Label>Error</Form.Label>\n        <DatePicker\n          value={datepickerValue}\n          onChange={date => {\n            setDatepickerValue(date)\n          }}\n          status='error'\n        />\n      </Form.Field>\n      <Form.Field>\n        <Form.Label>Warning</Form.Label>\n        <DatePicker\n          value={datepickerValue}\n          onChange={date => {\n            setDatepickerValue(date)\n          }}\n          status='warning'\n        />\n      </Form.Field>\n      <Form.Field>\n        <Form.Label>Success</Form.Label>\n        <DatePicker\n          value={datepickerValue}\n          onChange={date => {\n            setDatepickerValue(date)\n          }}\n          status='success'\n        />\n      </Form.Field>\n    </Form>\n  )\n}\n\nexport default Example\n";