export default "import { FormNonCompound as Form, Input } from '@toptal/picasso-forms'\nimport React from 'react'\n\nconst Example = () => {\n  return (\n    <Form\n      autoComplete='off'\n      onSubmit={values => window.alert(JSON.stringify(values, undefined, 2))}\n      layout='horizontal'\n      labelWidth={{ md: 4, lg: 3, xl: 2 }}\n    >\n      <Input\n        enableReset\n        onResetClick={(set: (value: string) => void) => {\n          set('')\n        }}\n        required\n        name='default-firstName'\n        label='First name'\n        placeholder='e.g. Bruce'\n      />\n    </Form>\n  )\n}\n\nexport default Example\n";