export default "import React, { useState } from 'react'\nimport {\n  Modal,\n  Button,\n  Input,\n  Checkbox,\n  Select,\n  Form,\n  DatePicker,\n} from '@toptal/picasso'\nimport { useModal } from '@toptal/picasso-utils'\n\nconst STATES = [\n  {\n    text: 'Alabama',\n    value: 'Alabama',\n  },\n  {\n    text: 'Utah',\n    value: 'Utah',\n  },\n]\n\nconst ModalDialog = ({\n  open,\n  onClose,\n}: {\n  open: boolean\n  onClose: () => void\n}) => {\n  const [isLoading, setLoading] = useState(false)\n  const [date, setDate] = useState<Date>()\n\n  return (\n    <Modal onClose={onClose} open={open}>\n      <Modal.Title>Edit address details</Modal.Title>\n      <Modal.Content>\n        <Form.Field>\n          <Input width='full' placeholder='City' value='Alabaster' />\n        </Form.Field>\n        <Form.Field>\n          <Input width='full' placeholder='Street' value='John Fruit' />\n        </Form.Field>\n        <Form.Field>\n          <Select placeholder='State' options={STATES} value='Alabama' />\n        </Form.Field>\n        <Form.Field>\n          <DatePicker\n            width='full'\n            value={date}\n            onChange={date => {\n              /* eslint-disable-next-line no-console */\n              console.log('selected date is: ', date)\n\n              setDate(date as Date)\n            }}\n          />\n        </Form.Field>\n        <Form.Field>\n          <Checkbox label='Use shipping address for billing' />\n        </Form.Field>\n      </Modal.Content>\n      <Modal.Actions>\n        <Button disabled={isLoading} variant='secondary' onClick={onClose}>\n          Cancel\n        </Button>\n        <Button\n          data-testid='close'\n          loading={isLoading}\n          onClick={() => {\n            setLoading(true)\n\n            setTimeout(() => {\n              setLoading(false)\n              onClose()\n            }, 1000)\n          }}\n          variant='positive'\n        >\n          Update\n        </Button>\n      </Modal.Actions>\n    </Modal>\n  )\n}\n\nconst Example = () => {\n  const { showModal, hideModal, isOpen } = useModal()\n\n  return (\n    <>\n      <Button data-testid='open' onClick={showModal}>\n        Open\n      </Button>\n      <ModalDialog open={isOpen} onClose={hideModal} />\n    </>\n  )\n}\n\nexport default Example\n";