export default "import React from 'react'\nimport { Container } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\nimport {\n  FormSpy,\n  FormNonCompound,\n  Input,\n  SubmitButton,\n} from '@toptal/picasso-forms'\n\nconst Example = () => (\n  <FormNonCompound\n    onSubmit={values => window.alert(JSON.stringify(values, undefined, 2))}\n  >\n    <Input\n      required\n      name='firstName'\n      label='First name'\n      placeholder='e.g. Bruce'\n    />\n\n    <FormSpy>\n      {({ values }) => (\n        <Input\n          required\n          name='lastName'\n          disabled={!values?.firstName}\n          label='Last name'\n          placeholder='Disabled until first name is filled out'\n        />\n      )}\n    </FormSpy>\n\n    <Container top={SPACING_4}>\n      <FormSpy>\n        {({ pristine, values }) => {\n          const isDisabled = pristine || !values?.lastName\n\n          return (\n            <SubmitButton disabled={isDisabled}>\n              {isDisabled ? 'Fill out form to enable' : 'Submit'}\n            </SubmitButton>\n          )\n        }}\n      </FormSpy>\n    </Container>\n  </FormNonCompound>\n)\n\nexport default Example\n";