export default "import type { ChangeEvent } from 'react'\nimport React, { useState } from 'react'\nimport { Select, Form, Container, NumberInput } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\n\nconst SelectSearchBehaviourExample = () => {\n  const [value, setValue] = useState<string>('')\n  const [threshold, setThreshold] = useState(4)\n\n  const handleChange = (\n    event: ChangeEvent<{\n      name?: string\n      value: string\n    }>\n  ) => {\n    setValue(event.target.value)\n  }\n\n  const handleThresholdChange = (\n    event: React.ChangeEvent<HTMLInputElement>\n  ) => {\n    setThreshold(parseInt(event.target.value, 10))\n  }\n\n  return (\n    <Container flex>\n      <Container right={SPACING_4}>\n        <Form.Field>\n          <Form.Label>Search for an option</Form.Label>\n          <Select\n            onChange={handleChange}\n            value={value}\n            options={OPTIONS}\n            placeholder='Choose an option...'\n            width='auto'\n            searchThreshold={threshold}\n            data-testid='select'\n          />\n        </Form.Field>\n      </Container>\n      <Container right={SPACING_4}>\n        <Form.Field>\n          <Form.Label>Search threshold</Form.Label>\n          <NumberInput\n            value={threshold}\n            onChange={handleThresholdChange}\n            data-testid='input-threshold'\n          />\n        </Form.Field>\n      </Container>\n      <Container>\n        <Form.Field>\n          <Form.Label>Search with input reset</Form.Label>\n          <Select\n            onChange={handleChange}\n            value={value}\n            options={OPTIONS}\n            placeholder='Choose an option...'\n            width='auto'\n            enableResetSearch\n            searchThreshold={threshold}\n            data-testid='select'\n          />\n        </Form.Field>\n      </Container>\n    </Container>\n  )\n}\n\nconst OPTIONS = [\n  { value: '1', text: 'Option 1' },\n  { value: '2', text: 'Option 2' },\n  { value: '3', text: 'Option 3' },\n  { value: '4', text: 'Option 4' },\n  { value: '5', text: 'Option 5' },\n]\n\nexport default SelectSearchBehaviourExample\n";