export default "import { Button, Typography, Container, Drawer } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\nimport React, { useState } from 'react'\n\nconst Example = () => {\n  const [open, setOpen] = useState(false)\n\n  return (\n    <div>\n      <Button data-testid='trigger' onClick={() => setOpen(!open)}>\n        Show drawer\n      </Button>\n      <Drawer\n        open={open}\n        disableBackdrop\n        onClose={() => setOpen(false)}\n        maintainBodyScrollLock={false}\n      >\n        <Container data-testid='content' padded={SPACING_4}>\n          <Typography>\n            The backdrop does not block the interaction with page content.\n          </Typography>\n        </Container>\n      </Drawer>\n    </div>\n  )\n}\n\nexport default Example\n";