export default "import React from 'react'\nimport { palette, SPACING_2, SPACING_4 } from '@toptal/picasso-utils'\nimport { LineChart } from '@toptal/picasso-charts'\nimport { Page, Paper, Container, Typography, Indicator } from '@toptal/picasso'\n\nconst CustomTooltip = ({ active, payload }: any) => {\n  if (active && payload && payload.length > 0) {\n    // eslint-disable-next-line id-length\n    const { x, infected, recovered, died } = payload[0].payload\n\n    return (\n      <Paper>\n        <Container padded={SPACING_2}>\n          <Typography size='medium'>Date: {x}</Typography>\n          <Container>\n            <Container inline right={SPACING_4}>\n              <Indicator color='yellow' />\n            </Container>\n            <Typography inline size='medium'>\n              Infected: {infected}\n            </Typography>\n          </Container>\n\n          <Container>\n            <Container inline right={SPACING_4}>\n              <Indicator color='red' />\n            </Container>\n            <Typography inline size='medium'>\n              Died: {died}\n            </Typography>\n          </Container>\n\n          <Container>\n            <Container inline right={SPACING_4}>\n              <Indicator color='green' />\n            </Container>\n            <Typography inline size='medium'>\n              Recovered: {recovered}\n            </Typography>\n          </Container>\n        </Container>\n      </Paper>\n    )\n  }\n\n  return null\n}\n\nconst Example = () => (\n  <Page.Content>\n    <Page.Article>\n      <LineChart\n        tooltip\n        xAxisKey='date'\n        customTooltip={<CustomTooltip />}\n        height={150}\n        unit=' cases'\n        data={CHART_DATA}\n        lineConfig={{\n          infected: { color: palette.yellow.main },\n          recovered: { color: palette.blue.main },\n          died: { color: palette.red.main },\n        }}\n      />\n    </Page.Article>\n  </Page.Content>\n)\n\nconst CHART_DATA = [\n  {\n    date: '20',\n    infected: 10,\n    recovered: 5,\n    died: 5,\n  },\n  {\n    date: '21',\n    infected: 9,\n    recovered: 6,\n    died: 3,\n  },\n  {\n    date: '22',\n    infected: 9,\n    recovered: 6,\n    died: 3,\n  },\n  {\n    date: '23',\n    infected: 8,\n    recovered: 4,\n    died: 4,\n  },\n  {\n    date: '24',\n    infected: 11,\n    recovered: 6,\n    died: 5,\n  },\n  {\n    date: '25',\n    infected: 7,\n    recovered: 7,\n    died: 0,\n  },\n  {\n    date: '26',\n    infected: 11,\n    recovered: 7,\n    died: 4,\n  },\n  {\n    date: '27',\n    infected: 7,\n    recovered: 4,\n    died: 3,\n  },\n  {\n    date: '28',\n    infected: 12,\n    recovered: 3,\n    died: 9,\n  },\n  {\n    date: '29',\n    infected: 8,\n    recovered: 6,\n    died: 2,\n  },\n  {\n    date: '30',\n    infected: 8,\n    recovered: 3,\n    died: 5,\n  },\n  {\n    date: '31',\n    infected: 12,\n    recovered: 4,\n    died: 8,\n  },\n  {\n    date: '01',\n    infected: 7,\n    recovered: 4,\n    died: 3,\n  },\n  {\n    date: '02',\n    infected: 10,\n    recovered: 4,\n    died: 6,\n  },\n  {\n    date: '03',\n    infected: 7,\n    recovered: 7,\n    died: 0,\n  },\n  {\n    date: '04',\n    infected: 8,\n    recovered: 5,\n    died: 3,\n  },\n  {\n    date: '05',\n    infected: 11,\n    recovered: 7,\n    died: 4,\n  },\n  {\n    date: '06',\n    infected: 8,\n    recovered: 3,\n    died: 5,\n  },\n  {\n    date: '07',\n    infected: 11,\n    recovered: 3,\n    died: 8,\n  },\n  {\n    date: '08',\n    infected: 7,\n    recovered: 6,\n    died: 1,\n  },\n  {\n    date: '09',\n    infected: 12,\n    recovered: 4,\n    died: 8,\n  },\n  {\n    date: '10',\n    infected: 11,\n    recovered: 6,\n    died: 5,\n  },\n]\n\nexport default Example\n";