export default "import React from 'react'\nimport { Radio, Container, Typography } from '@toptal/picasso'\nimport { SPACING_2, SPACING_6 } from '@toptal/picasso-utils'\nimport styled from 'styled-components'\n\nconst Label = styled.label`\n  display: flex;\n  cursor: pointer;\n`\n\nconst List = styled.ul`\n  padding-left: 20px;\n  font-size: 12px;\n  margin: 0;\n`\n\nconst CustomRadio = () => {\n  return (\n    <Container flex alignItems='center'>\n      <Container right={SPACING_2} flex alignItems='center'>\n        <Radio id='id-1' />\n      </Container>\n      <Label htmlFor='id-1'>\n        <Typography weight='semibold' size='large'>\n          Payoneer\n        </Typography>\n      </Label>\n    </Container>\n  )\n}\n\nconst Benefits = () => {\n  return (\n    <Container>\n      <List>\n        <li>\n          <Typography size='xsmall'>\n            Similar benefits to Toptal Payments\n          </Typography>\n        </li>\n        <li>\n          <Typography size='xsmall'>\n            Instantly transfer funds to a prepaid card{' '}\n          </Typography>\n        </li>\n      </List>\n    </Container>\n  )\n}\n\nconst PayoneerLogo = () => {\n  return (\n    <Container flex alignItems='center'>\n      <img src='./payoneer-logo.png' />\n    </Container>\n  )\n}\n\nconst PayoneerPicker = () => {\n  return (\n    <Container\n      flex\n      alignItems='center'\n      justifyContent='space-between'\n      bottom={SPACING_2}\n    >\n      <CustomRadio />\n      <PayoneerLogo />\n    </Container>\n  )\n}\n\nconst Example = () => (\n  <div>\n    <Container\n      rounded\n      padded={SPACING_6}\n      variant='blue'\n      style={{ maxWidth: 400 }}\n    >\n      <PayoneerPicker />\n      <Benefits />\n    </Container>\n  </div>\n)\n\nexport default Example\n";