export default "import React from 'react'\nimport type { TreeNodeInterface } from '@toptal/picasso'\nimport {\n  TreeView,\n  TreeNodeAvatar,\n  Button,\n  Container,\n  Modal,\n  UserBadge,\n} from '@toptal/picasso'\nimport type { HierarchyPointNode } from 'd3-hierarchy'\nimport { useModal, palette } from '@toptal/picasso-utils'\nimport styled from 'styled-components'\n\nconst NodeContainer = styled<typeof Container>(Container)<{\n  selected?: boolean\n}>`\n  display: flex;\n  align-items: center;\n  width: 236px;\n  padding: 0.5rem;\n  ${({ selected }) =>\n    `border: 1px solid ${selected ? palette.blue.main : palette.grey.light2};`}\n`\n\nconst createTreeNode = (\n  override: Partial<TreeNodeInterface> = {}\n): TreeNodeInterface => {\n  return {\n    id: '1',\n    disabled: false,\n    selected: false,\n    children: [],\n    info: {\n      name: 'NODE+NAME+1',\n    },\n    ...override,\n  }\n}\n\nconst createTree = (): TreeNodeInterface => {\n  return createTreeNode({\n    id: '1',\n    selected: true,\n    info: {\n      name: 'NODE+1',\n    },\n    children: [\n      createTreeNode({\n        id: '2',\n        info: {\n          name: 'NODE+2',\n        },\n        children: [\n          createTreeNode({\n            id: '3',\n            info: {\n              name: 'NODE+3',\n            },\n            children: [\n              createTreeNode({\n                id: '3.1',\n                info: {\n                  name: 'NODE+3.1',\n                },\n                children: [\n                  createTreeNode({\n                    id: '3.1.1',\n                    info: {\n                      name: 'NODE+3.1.1',\n                    },\n                  }),\n                  createTreeNode({\n                    id: '3.1.2',\n                    info: {\n                      name: 'NODE+3.1.2',\n                    },\n                  }),\n                ],\n              }),\n              createTreeNode({\n                id: '3.2',\n                info: {\n                  name: 'NODE+3.2',\n                },\n                children: [\n                  createTreeNode({\n                    id: '3.2.1',\n                    info: {\n                      name: 'NODE+3.2.1',\n                    },\n                  }),\n                  createTreeNode({\n                    id: '3.2.2',\n                    info: {\n                      name: 'NODE+3.2.2',\n                    },\n                  }),\n                ],\n              }),\n            ],\n          }),\n        ],\n      }),\n      createTreeNode({\n        id: '4',\n        info: {\n          name: 'NODE+4',\n        },\n        children: [\n          createTreeNode({\n            id: '4.1',\n            info: {\n              name: 'NODE+4.1',\n            },\n            children: [\n              createTreeNode({\n                id: '4.1.1',\n                info: {\n                  name: 'NODE+4.1.1',\n                },\n              }),\n              createTreeNode({\n                id: '4.1.2',\n                info: {\n                  name: 'NODE+4.1.2',\n                },\n              }),\n            ],\n          }),\n        ],\n      }),\n    ],\n  })\n}\n\nconst rootNode = createTree()\n\nconst renderNode = (pointNode: HierarchyPointNode<TreeNodeInterface>) => {\n  if (pointNode.data.id === '2') {\n    return (\n      <NodeContainer>\n        <div>\n          <UserBadge\n            name='QQQQQQQQ QQQQQQQQ'\n            avatar={\n              <TreeNodeAvatar\n                name='QQQQQQQQ QQQQQQQQ'\n                src='./jacqueline-with-flowers-1954-square.jpg'\n              />\n            }\n          />\n          <UserBadge\n            name='QQQQQQQQ QQQQQQQQ'\n            avatar={<TreeNodeAvatar name='QQQQQQQQ QQQQQQQQ' />}\n          />\n          <UserBadge\n            name='QQQQQQQQ QQQQQQQQ'\n            avatar={<TreeNodeAvatar name='QQQQQQQQ QQQQQQQQ' />}\n          />\n          <UserBadge\n            name='QQQQQQQQ QQQQQQQQ'\n            avatar={<TreeNodeAvatar name='QQQQQQQQ QQQQQQQQ' />}\n          />\n          <UserBadge\n            name='QQQQQQQQ QQQQQQQQ'\n            avatar={<TreeNodeAvatar name='QQQQQQQQ QQQQQQQQ' />}\n          />\n        </div>\n      </NodeContainer>\n    )\n  }\n\n  return (\n    <NodeContainer>\n      <UserBadge\n        name={pointNode.data.info.name}\n        avatar={<TreeNodeAvatar name={pointNode.data.info.name} />}\n      />\n    </NodeContainer>\n  )\n}\n\nconst ModalTreeDialog = ({\n  open,\n  onClose,\n}: {\n  open: boolean\n  onClose: () => void\n}) => {\n  return (\n    <Modal onClose={onClose} open={open} size='full-screen'>\n      <Modal.Title>Modal Tree View</Modal.Title>\n      <Modal.Content data-testid='tree-dialog-content'>\n        <TreeView data={rootNode} renderNode={renderNode} />\n      </Modal.Content>\n    </Modal>\n  )\n}\n\nconst Example = () => {\n  const { showModal, hideModal, isOpen } = useModal()\n\n  return (\n    <>\n      <Button data-testid='open' onClick={showModal}>\n        Open\n      </Button>\n      <ModalTreeDialog open={isOpen} onClose={hideModal} />\n    </>\n  )\n}\n\nexport default Example\n";