export default "import React from 'react'\nimport { Tabs, Button, Link, PageHead, Breadcrumbs } from '@toptal/picasso'\n\nconst DefaultExample = () => {\n  const [value, setValue] = React.useState(0)\n\n  const handleChange = (_: React.ChangeEvent<{}>, newValue: number) => {\n    setValue(newValue)\n  }\n\n  return (\n    <PageHead>\n      <Breadcrumbs>\n        <Breadcrumbs.Item\n          as={Link}\n          variant='action'\n          href='https://en.wikipedia.org/wiki/United_States'\n        >\n          USA\n        </Breadcrumbs.Item>\n        <Breadcrumbs.Item\n          as={Link}\n          variant='action'\n          href='https://en.wikipedia.org/wiki/Software'\n        >\n          Software\n        </Breadcrumbs.Item>\n        <Breadcrumbs.Item as={Link} variant='action' href='https://toptal.com'>\n          Toptal\n        </Breadcrumbs.Item>\n      </Breadcrumbs>\n      <PageHead.Main>\n        <PageHead.Title>Heading Large</PageHead.Title>\n        <PageHead.Actions>\n          <Button size='small' variant='secondary'>\n            Button\n          </Button>\n          <Button size='small' variant='secondary'>\n            Button\n          </Button>\n          <Button size='small' variant='secondary'>\n            Button\n          </Button>\n        </PageHead.Actions>\n      </PageHead.Main>\n      <PageHead.Tabs>\n        <Tabs value={value} onChange={handleChange}>\n          <Tabs.Tab label='Label' />\n          <Tabs.Tab label='Label' />\n          <Tabs.Tab label='Label' />\n        </Tabs>\n      </PageHead.Tabs>\n    </PageHead>\n  )\n}\n\nexport default DefaultExample\n";