export default "import React, { useState } from 'react'\nimport {\n  QueryBuilder,\n  type RuleGroupTypeAny,\n} from '@toptal/picasso-query-builder'\n\nconst initialQuery: RuleGroupTypeAny = {\n  rules: [\n    {\n      field: 'field1',\n      operator: '=',\n      valueSource: 'value',\n      value: 'John',\n    },\n    {\n      field: 'field2',\n      operator: '=',\n      valueSource: 'value',\n      value: 'John',\n    },\n  ],\n  combinator: 'and',\n}\n\nconst fields = [\n  {\n    name: 'field1',\n    label: 'First name',\n    tooltip: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit.',\n  },\n  {\n    name: 'field2',\n    label: 'Last name',\n  },\n]\n\nconst Example = () => {\n  const [query, setQuery] = useState<RuleGroupTypeAny>(initialQuery)\n\n  const handleQueryChange = (newQuery: RuleGroupTypeAny) => {\n    setQuery(newQuery)\n  }\n\n  return (\n    <QueryBuilder\n      fields={fields}\n      query={query}\n      onQueryChange={handleQueryChange}\n    />\n  )\n}\n\nexport default Example\n";