export default "import React from 'react'\nimport { Pagination, Container, Typography } from '@toptal/picasso'\nimport { SPACING_2, SPACING_4 } from '@toptal/picasso-utils'\n\nconst Example = () => (\n  <Container flex direction='column' justifyContent='space-between'>\n    <Container bottom={SPACING_2}>\n      <Typography variant='heading' size='small'>\n        0 or 1 pages\n      </Typography>\n      <Typography size='xsmall'>~ NULL ~</Typography>\n    </Container>\n    <Container bottom={SPACING_4}>\n      <Pagination\n        activePage={1}\n        onPageChange={handlePageChange}\n        totalPages={1}\n      />\n    </Container>\n\n    <Container bottom={SPACING_2}>\n      <Typography variant='heading' size='small'>\n        No ellipsises\n      </Typography>\n    </Container>\n    <Container bottom={SPACING_4}>\n      <Pagination\n        activePage={3}\n        onPageChange={handlePageChange}\n        totalPages={5}\n      />\n    </Container>\n\n    <Container bottom={SPACING_2}>\n      <Typography variant='heading' size='small'>\n        End ellipsis\n      </Typography>\n    </Container>\n    <Container bottom={SPACING_4}>\n      <Pagination\n        activePage={1}\n        onPageChange={handlePageChange}\n        totalPages={5}\n      />\n    </Container>\n\n    <Container bottom={SPACING_2}>\n      <Typography variant='heading' size='small'>\n        Start ellipsis\n      </Typography>\n    </Container>\n    <Container bottom={SPACING_4}>\n      <Pagination\n        activePage={5}\n        onPageChange={handlePageChange}\n        totalPages={5}\n      />\n    </Container>\n\n    <Container bottom={SPACING_2}>\n      <Typography variant='heading' size='small'>\n        Two ellipsises\n      </Typography>\n    </Container>\n    <Container bottom={SPACING_4}>\n      <Pagination\n        activePage={1234}\n        onPageChange={handlePageChange}\n        totalPages={10000}\n      />\n    </Container>\n\n    <Container bottom={SPACING_2}>\n      <Typography variant='heading' size='small'>\n        Custom siblings count\n      </Typography>\n    </Container>\n    <Container bottom={SPACING_4}>\n      <Pagination\n        activePage={1234}\n        onPageChange={handlePageChange}\n        totalPages={10000}\n        siblingCount={4}\n      />\n    </Container>\n  </Container>\n)\n\nconst handlePageChange = (page: number) => {\n  window.alert('Page changed to ' + page)\n}\n\nexport default Example\n";