export default "import React from 'react'\nimport type { TreeNodeInterface } from '@toptal/picasso'\nimport {\n  TreeNodeAvatar,\n  Container,\n  UserBadge,\n  StaticTreeView,\n} from '@toptal/picasso'\nimport type { HierarchyPointNode } from 'd3-hierarchy'\nimport styled from 'styled-components'\nimport { palette } from '@toptal/picasso-utils'\n\nconst NodeContainer = styled<typeof Container>(Container)<{\n  selected?: boolean\n}>`\n  display: flex;\n  align-items: center;\n  width: 236px;\n  padding: 0.5rem;\n  ${({ selected }) =>\n    `border: 1px solid ${selected ? palette.blue.main : palette.grey.light2};`}\n`\n\nconst createTreeNode = (\n  override: Partial<TreeNodeInterface> = {}\n): TreeNodeInterface => {\n  return {\n    id: '1',\n    disabled: false,\n    selected: false,\n    children: [],\n    info: {\n      name: 'NODE+NAME+1',\n    },\n    ...override,\n  }\n}\n\nlet id = 0\nconst getId = () => {\n  id += 1\n\n  return String(id)\n}\n\nconst createTree = (): TreeNodeInterface => {\n  return createTreeNode({\n    id: getId(),\n    selected: true,\n    info: {\n      name: 'NODE-1',\n    },\n    children: [\n      createTreeNode({\n        id: getId(),\n        info: {\n          name: 'NODE-1-1',\n        },\n        children: [\n          ...Array(3)\n            .fill(undefined)\n            .map((_, index) =>\n              createTreeNode({\n                id: getId(),\n                info: {\n                  name: `NODE-1-1-${index + 1}-before`,\n                },\n                children: [],\n              })\n            ),\n          createTreeNode({\n            id: getId(),\n            info: {\n              name: 'NODE-1-1-N',\n            },\n            children: Array(8)\n              .fill(undefined)\n              .map((_, index) =>\n                createTreeNode({\n                  id: getId(),\n                  info: {\n                    name: `NODE-1-1-1-${index + 1}`,\n                  },\n                  children: [],\n                })\n              ),\n          }),\n          ...Array(8)\n            .fill(undefined)\n            .map((_, index) =>\n              createTreeNode({\n                id: getId(),\n                info: {\n                  name: `NODE-1-1-${index + 1}-after`,\n                },\n                children: [],\n              })\n            ),\n        ],\n      }),\n    ],\n  })\n}\n\nconst rootNode = createTree()\n\nconst renderNode = (pointNode: HierarchyPointNode<TreeNodeInterface>) => {\n  return (\n    <NodeContainer>\n      <UserBadge\n        name={pointNode.data.info.name}\n        avatar={\n          <TreeNodeAvatar name={pointNode.data.info.name} size='xsmall' />\n        }\n      />\n    </NodeContainer>\n  )\n}\n\nconst Example = () => (\n  <Container style={{ display: 'grid', placeItems: 'center' }}>\n    <Container style={{ minHeight: '25rem', width: '100%', maxWidth: 1200 }}>\n      <StaticTreeView\n        data={rootNode}\n        renderNode={renderNode}\n        directionProps={{\n          verticalMargin: 20,\n          horizontalMargin: 200,\n          direction: 'horizontal',\n          variant: 'compact',\n        }}\n      />\n    </Container>\n  </Container>\n)\n\nexport default Example\n";