export default "import React, { useState } from 'react'\nimport { Button } from '@toptal/picasso'\n\nconst Example = () => {\n  const [active, setActive] = useState(1)\n\n  return (\n    <div>\n      <Button.Group>\n        <Button.Group.Item\n          active={active === 0}\n          onClick={() => setActive(0)}\n          disabled\n        >\n          First\n        </Button.Group.Item>\n        <Button.Group.Item\n          active={active === 1}\n          onClick={() => setActive(1)}\n          disabled\n        >\n          Second\n        </Button.Group.Item>\n        <Button.Group.Item\n          active={active === 2}\n          onClick={() => setActive(2)}\n          disabled\n        >\n          Third\n        </Button.Group.Item>\n        <Button.Group.Item\n          active={active === 3}\n          onClick={() => setActive(3)}\n          disabled\n        >\n          Fourth\n        </Button.Group.Item>\n      </Button.Group>\n    </div>\n  )\n}\n\nexport default Example\n";