export default "import React from 'react'\nimport { Container } from '@toptal/picasso'\nimport { SPACING_6, palette } from '@toptal/picasso-utils'\nimport { BarChart } from '@toptal/picasso-charts'\n\nconst CHART_DATA = [\n  {\n    name: 'Apple',\n    value: { 'engineers hired': 500 },\n  },\n  {\n    name: 'Google',\n    value: { 'engineers hired': 700 },\n  },\n  {\n    name: 'Facebook',\n    value: { 'engineers hired': 600 },\n  },\n  {\n    name: 'Amazon',\n    value: { 'engineers hired': 400 },\n  },\n  {\n    name: 'Toptal',\n    value: { 'engineers hired': 1000 },\n  },\n]\n\nconst Example = () => (\n  <div style={{ width: 720 }}>\n    <Container bottom={SPACING_6}>\n      <BarChart\n        data={CHART_DATA}\n        getBarColor={() => palette.blue.main}\n        width='100%'\n        tooltip\n        maxBarSize={80}\n        autoSize\n      />\n    </Container>\n    <Container>\n      <BarChart\n        height={300}\n        data={CHART_DATA}\n        layout='vertical'\n        getBarColor={() => palette.blue.main}\n        width='100%'\n        tooltip\n        showBarLabel={false}\n        maxBarSize={40}\n        autoSize\n      />\n    </Container>\n  </div>\n)\n\nexport default Example\n";