export default "import type { ReactNode } from 'react'\nimport React, { useState } from 'react'\nimport {\n  Container,\n  PortfolioDesigner16,\n  Profile16,\n  Globe16,\n  Page,\n  Menu,\n  Typography,\n  Update16,\n  Button,\n  Grid,\n  Image,\n  SkeletonLoader,\n} from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\n\nconst useGetData = (): [boolean, () => void] => {\n  const [loading, setLoading] = useState(true)\n\n  if (loading) {\n    setTimeout(() => setLoading(false), 2000)\n  }\n\n  const reload = () => {\n    setLoading(true)\n  }\n\n  return [loading, reload]\n}\n\nconst SidebarMenu = ({ children }: { children: ReactNode }) => (\n  <Page.Sidebar>\n    <Page.Sidebar.Menu>\n      <Page.Sidebar.Item icon={<PortfolioDesigner16 />}>Home</Page.Sidebar.Item>\n      <Page.Sidebar.Item icon={<Profile16 />}>Contacts</Page.Sidebar.Item>\n      <Page.Sidebar.Item icon={<Globe16 />}>Team</Page.Sidebar.Item>\n    </Page.Sidebar.Menu>\n    <Page.Sidebar.Menu bottom>{children}</Page.Sidebar.Menu>\n  </Page.Sidebar>\n)\n\nconst RightContent = () => (\n  <Page.TopBarMenu\n    name='Jacqueline Roque'\n    avatar='./jacqueline-with-flowers-1954-square.jpg'\n  >\n    <Menu>\n      <Menu.Item>My Account</Menu.Item>\n      <Menu.Item>Log Out</Menu.Item>\n    </Menu>\n  </Page.TopBarMenu>\n)\n\nconst Content = () => (\n  <>\n    <Container flex justifyContent='space-between' alignItems='center'>\n      <Typography align='center' variant='heading' size='large'>\n        My Page\n      </Typography>\n      <Button>Read more</Button>\n    </Container>\n\n    <p>\n      Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod\n      tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim\n      veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea\n      commodo consequat. Duis aute irure dolor in reprehenderit in voluptate\n      velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat\n      cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id\n      est laborum.\n    </p>\n\n    <Grid>\n      <Grid.Item sm={6}>\n        <Typography align='center' variant='heading'>\n          My section\n        </Typography>\n        <Container flex justifyContent='center'>\n          <Image\n            src='./jacqueline-with-flowers-1954-square.jpg'\n            alt='Default image'\n            style={{ width: '5rem', height: '5rem' }}\n          />\n        </Container>\n        <Typography>\n          Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do\n          eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad\n          minim veniam, quis nostrud exercitation ullamco laboris nisi ut\n          aliquip ex ea commodo consequat.\n        </Typography>\n      </Grid.Item>\n      <Grid.Item sm={6}>\n        <Typography align='center' variant='heading'>\n          My Section\n        </Typography>\n        <Typography>\n          Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do\n          eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad\n          minim veniam, quis nostrud exercitation ullamco laboris nisi ut\n          aliquip ex ea commodo consequat. Lorem ipsum dolor sit amet,\n          consectetur adipiscing elit, sed do eiusmod tempor incididunt ut\n          labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud\n          exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat.\n        </Typography>\n      </Grid.Item>\n    </Grid>\n  </>\n)\n\nconst PageLoader = () => (\n  <>\n    <Container\n      flex\n      justifyContent='space-between'\n      alignItems='center'\n      bottom={SPACING_4}\n    >\n      <SkeletonLoader.Header />\n      <SkeletonLoader.Button />\n    </Container>\n\n    <Container bottom={SPACING_4}>\n      <SkeletonLoader.Typography rows={4} />\n    </Container>\n\n    <Grid>\n      <Grid.Item sm={6}>\n        <Container\n          flex\n          alignItems='center'\n          bottom={SPACING_4}\n          direction='column'\n        >\n          <SkeletonLoader.Header />\n\n          <SkeletonLoader.Media variant='image' width='5rem' height='5rem' />\n        </Container>\n\n        <SkeletonLoader.Typography rows={5} />\n      </Grid.Item>\n\n      <Grid.Item sm={6}>\n        <Container flex justifyContent='center' bottom={SPACING_4}>\n          <SkeletonLoader.Header />\n        </Container>\n        <SkeletonLoader.Typography rows={8} />\n      </Grid.Item>\n    </Grid>\n  </>\n)\n\nconst PageExample = () => {\n  const [loading, reloadData] = useGetData()\n\n  return (\n    <div style={{ height: '40rem' }}>\n      <Page>\n        <Page.TopBar rightContent={<RightContent />} title='Default example' />\n        <Page.Content>\n          <SidebarMenu>\n            <Page.Sidebar.Item icon={<Update16 />} onClick={reloadData}>\n              Click me to reload the content!\n            </Page.Sidebar.Item>\n          </SidebarMenu>\n          <Container\n            style={{ flex: 1 }}\n            top={SPACING_4}\n            bottom={SPACING_4}\n            left={SPACING_4}\n            right={SPACING_4}\n          >\n            {loading ? PageLoader() : <Content />}\n          </Container>\n        </Page.Content>\n        <Page.Footer />\n      </Page>\n    </div>\n  )\n}\n\nexport default PageExample\n";