export default "import React, { useState } from 'react'\nimport {\n  QueryBuilder,\n  type RuleGroupTypeAny,\n} from '@toptal/picasso-query-builder'\nimport { Container } from '@toptal/picasso-container'\nimport { Loader } from '@toptal/picasso-loader'\n\nconst initialQuery: RuleGroupTypeAny = {\n  rules: [\n    {\n      field: 'name',\n      operator: '=',\n      valueSource: 'value',\n      value: 'John',\n    },\n    {\n      field: 'age',\n      operator: '=',\n      valueSource: 'value',\n      value: '12',\n    },\n  ],\n  combinator: 'and',\n}\n\nconst fields = [\n  {\n    name: 'name',\n    label: 'Name',\n    type: 'text',\n  },\n  {\n    name: 'age',\n    label: 'Age',\n    type: 'number',\n  },\n]\n\nconst Example = () => {\n  const [query, setQuery] = useState<RuleGroupTypeAny>(initialQuery)\n\n  const handleQueryChange = (newQuery: RuleGroupTypeAny) => {\n    setQuery(newQuery)\n  }\n\n  const renderTotalCount = ({\n    totalCountLoading,\n    totalCount,\n  }: {\n    totalCountLoading: boolean\n    totalCount: number\n  }) => {\n    if (totalCountLoading) {\n      return (\n        <Container left='small'>\n          <Loader size='small' variant='inherit' />\n        </Container>\n      )\n    }\n\n    return totalCount !== undefined && `(${totalCount})`\n  }\n\n  return (\n    <QueryBuilder\n      fields={fields}\n      query={query}\n      onQueryChange={handleQueryChange}\n      runQueryButtonContent={\n        <>\n          Custom Text{' '}\n          {renderTotalCount({ totalCount: 15, totalCountLoading: false })}\n        </>\n      }\n    />\n  )\n}\n\nexport default Example\n";