export default "import React from 'react'\nimport { Container, Page } from '@toptal/picasso'\nimport { palette } from '@toptal/picasso-utils'\nimport { AnalyticsChart } from '@topkit/analytics-charts'\n\ntype Payload = {\n  name: string\n  value: number\n  payload: Record<string, number | boolean>\n}\n\nconst CustomTooltip = ({\n  active,\n  payload,\n}: {\n  active?: boolean\n  payload?: Payload[]\n}) => {\n  if (!active || !payload) {\n    return null\n  }\n\n  return (\n    <Container style={{ background: '#fff' }}>\n      {payload.map(({ name, value, payload: data }) => (\n        <Container key={name}>\n          <b>{name}</b>: {data[`${name}IsEmpty`] ? 'No data provided.' : value}\n        </Container>\n      ))}\n    </Container>\n  )\n}\n\nconst Example = () => (\n  <Page.Content>\n    <Page.Article>\n      <AnalyticsChart\n        tooltip\n        customTooltip={<CustomTooltip />}\n        data={CHART_DATA}\n        lineConfig={{\n          role: { color: palette.yellow.main },\n          team: { color: palette.blue.main },\n        }}\n      />\n    </Page.Article>\n  </Page.Content>\n)\n\nconst CHART_DATA = [\n  {\n    id: 'role',\n    values: {\n      '2020-10-20': 0.0,\n      '2020-10-21': 0.0,\n      '2020-10-22': 0.0,\n      '2020-10-23': 0.0,\n      '2020-10-24': 0.0,\n      '2020-10-25': 0.0,\n      '2020-10-26': null,\n      '2020-10-27': 0.0,\n      '2020-10-28': 0.0,\n      '2020-10-29': 0.0,\n      '2020-10-30': 1.0,\n      '2020-10-31': 1.0,\n      '2020-11-01': 0.0,\n      '2020-11-02': null,\n      '2020-11-03': 0.0,\n      '2020-11-04': 0.0,\n      '2020-11-05': 0.0,\n      '2020-11-06': 0.0,\n      '2020-11-07': 2.0,\n      '2020-11-08': 0.0,\n      '2020-11-09': 0.0,\n      '2020-11-10': 0.0,\n    },\n  },\n  {\n    id: 'team',\n    values: {\n      '2020-10-20': 1.7,\n      '2020-10-21': 2,\n      '2020-10-22': 1.7,\n      '2020-10-23': 2,\n      '2020-10-24': 1.5,\n      '2020-10-25': 1.3,\n      '2020-10-26': 1.6,\n      '2020-10-27': 2.7,\n      '2020-10-28': 3.7,\n      '2020-10-29': null,\n      '2020-10-30': 1.5,\n      '2020-10-31': 1.6,\n      '2020-11-01': 2,\n      '2020-11-02': 1.5,\n      '2020-11-03': 1.3,\n      '2020-11-04': 1.5,\n      '2020-11-05': 1.5,\n      '2020-11-06': 1.8,\n      '2020-11-07': null,\n      '2020-11-08': 2,\n      '2020-11-09': 2,\n      '2020-11-10': 3.1,\n    },\n  },\n]\n\nexport default Example\n";