export default "import React from 'react'\nimport { Dropzone } from '@toptal/picasso'\n\nconst value = [\n  {\n    uploading: true,\n    progress: 30,\n    file: new File(['resume.pdf'], 'resume.pdf'),\n  },\n]\n\nconst Example = () => {\n  return (\n    <Dropzone\n      value={value}\n      hint='Max file size: 25MB'\n      accept={{\n        'image/*': [],\n      }}\n    />\n  )\n}\n\nexport default Example\n";