export default "/* eslint-disable max-lines */\nimport React, { useState } from 'react'\nimport type { Field, OptionGroup } from '@toptal/picasso-query-builder'\nimport {\n  QueryBuilder,\n  type RuleGroupTypeAny,\n} from '@toptal/picasso-query-builder'\nimport { Accordion, Container } from '@toptal/picasso'\n\nconst initialQuery: RuleGroupTypeAny = {\n  rules: [\n    {\n      field: 'firstName',\n      operator: '=',\n      valueSource: 'value',\n      value: 'John',\n    },\n    {\n      field: 'lastName',\n      operator: 'beginsWith',\n      valueSource: 'value',\n      value: 'Doe',\n    },\n    {\n      field: 'instrument',\n      operator: '=',\n      valueSource: 'value',\n      value: 'Steelpan',\n    },\n    {\n      rules: [\n        {\n          field: 'alsoPlays',\n          operator: 'contains',\n          valueSource: 'value',\n          value: 'More cowbell,Clapstick,Cowbell',\n        },\n        {\n          field: 'groupedField1',\n          operator: '=',\n          valueSource: 'field',\n          value: 'groupedField2',\n        },\n      ],\n      combinator: 'and',\n      not: false,\n    },\n  ],\n  combinator: 'and',\n}\n\nconst musicalInstruments: OptionGroup[] = [\n  {\n    label: 'Percussion instruments',\n    instruments: [\n      'Clapstick',\n      'Cowbell',\n      'Cymbal',\n      'Gong',\n      'Maraca',\n      'Marimba',\n      'More cowbell',\n      'Spoon',\n      'Steelpan',\n      'Tambourine',\n      'Triangle',\n      'Vibraphone',\n      'Washboard',\n      'Wood block',\n      'Wooden fish',\n      'Xylophone',\n    ],\n  },\n  {\n    label: 'Membranophones',\n    instruments: [\n      'Barrel drum',\n      'Bass drum',\n      'Bongo drums',\n      'Conga',\n      'Drum',\n      'Drum kit',\n      \"Jew's harp\",\n      'Octaban',\n      'Samphor',\n      'Snare drum',\n      'Timpani',\n      'Tom-tom',\n    ],\n  },\n  {\n    label: 'Wind instruments',\n    instruments: [\n      'Accordion',\n      'Air horn',\n      'Bagpipe',\n      'Baritone horn',\n      'Bassoon',\n      'Bazooka',\n      'Beatboxing',\n      'Blown bottle',\n      'Bugle',\n      'Clarinet',\n      'Conch',\n      'Cornet',\n      'Didgeridoo',\n      'Double bell euphonium',\n      'Doulophone',\n      'English horn',\n      'Euphonium',\n      'Flugelhorn',\n      'Flute',\n      'French horn',\n      'Harmonica',\n      'Irish flute',\n      'Jug',\n      'Kazoo',\n      'Melodeon',\n      'Mezzo-soprano',\n      'Oboe',\n      'Ocarina',\n      'Pan flute',\n      'Piccolo',\n      'Pipe organ',\n      'Recorder',\n      'Saxophone',\n      'Slide whistle',\n      'Sousaphone',\n      'Trombone',\n      'Trumpet',\n      'Tuba',\n      'Whistle',\n    ],\n  },\n  {\n    label: 'Stringed instruments',\n    instruments: [\n      'Aeolian harp',\n      'Bandolin',\n      'Banjo ukulele',\n      'Cello',\n      'Chapman stick',\n      'Clavichord',\n      'Clavinet',\n      'Double bass',\n      'Dulcimer',\n      'Fiddle',\n      'Guitar',\n      'Hammered dulcimer',\n      'Harp',\n      'Harpsichord',\n      'Lute',\n      'Lyre',\n      'Maguhu',\n      'Mandola',\n      'Mandolin',\n      'Octobass',\n      'Piano',\n      'Sitar',\n      'Ukulele',\n      'Viol',\n      'Violin',\n      'Washtub bass',\n    ],\n  },\n  {\n    label: 'Electronic instruments',\n    instruments: [\n      'AlphaSphere',\n      'Audiocubes',\n      'Bass pedals',\n      'Continuum Fingerboard',\n      'Croix Sonore',\n      \"Denis d'or\",\n      'Dubreq stylophone',\n      'Drum machine',\n      'Eigenharp',\n      'Electric guitar',\n      'Electronic keyboard',\n      'Electronic organ',\n      'EWI',\n      'Fingerboard synthesizer',\n      'Hammond organ',\n      'Keyboard',\n      'Keytar',\n      'Kraakdoos',\n      'Laser harp',\n      'Mellotron',\n      'MIDI keyboard',\n      'Omnichord',\n      'Ondes Martenot',\n      'Otamatone',\n      'Sampler',\n      'Seaboard music instrument',\n      'Skoog',\n      'Synclavier',\n      'Synthesizer',\n      'Teleharmonium',\n      'Tenori-on',\n      'Theremin',\n      'trautonium',\n      'Turntablism',\n      'Turntable',\n    ],\n  },\n].map(({ label, instruments }) => ({\n  label,\n  options: instruments.map(instrument => ({\n    name: instrument,\n    label: instrument,\n  })),\n}))\n\nconst fields: Field[] = [\n  {\n    name: 'firstName',\n    label: 'First Name',\n    placeholder: 'Enter first name',\n    inputType: 'text',\n  },\n  {\n    name: 'boolfield',\n    label: 'Boolean Field',\n    valueEditorType: 'boolean',\n  },\n  {\n    name: 'lastName',\n    label: 'Last Name',\n    placeholder: 'Enter last name',\n    defaultOperator: 'beginsWith',\n  },\n  { name: 'age', label: 'Age', inputType: 'number' },\n  {\n    name: 'instrument',\n    label: 'Primary instrument',\n    valueEditorType: 'select',\n    values: musicalInstruments,\n    defaultValue: 'Cowbell',\n  },\n  {\n    name: 'alsoPlays',\n    label: 'Also plays',\n    valueEditorType: 'multiselect',\n    values: musicalInstruments,\n    defaultValue: 'More cowbell',\n  },\n  { name: 'height', label: 'Height', inputType: 'number' },\n  { name: 'job', label: 'Job', inputType: 'text' },\n  {\n    name: 'groupedField1',\n    label: 'Grouped Field 1',\n    comparator: 'group',\n    group: 'group1',\n    valueSources: ['field', 'value'],\n  },\n  {\n    name: 'groupedField2',\n    label: 'Grouped Field 2',\n    comparator: 'group',\n    group: 'group1',\n    valueSources: ['field', 'value'],\n  },\n  {\n    name: 'groupedField3',\n    label: 'Grouped Field 3',\n    comparator: 'group',\n    group: 'group1',\n    valueSources: ['field', 'value'],\n  },\n  {\n    name: 'groupedField4',\n    label: 'Grouped Field 4',\n    comparator: 'group',\n    group: 'group1',\n    valueSources: ['field', 'value'],\n  },\n  {\n    name: 'rangeInput',\n    label: 'Some Range',\n    valueEditorType: 'range',\n    icon: '$',\n    min: 0,\n    step: 10,\n  },\n]\n\nconst Example = () => {\n  const [query, setQuery] = useState<RuleGroupTypeAny>(initialQuery)\n\n  const handleQueryChange = (newQuery: RuleGroupTypeAny) => {\n    setQuery(newQuery)\n  }\n\n  return (\n    <>\n      <QueryBuilder\n        fields={fields}\n        query={query}\n        onQueryChange={handleQueryChange}\n      />\n      <Container top='medium'>\n        <Accordion content={<pre>{JSON.stringify(query, null, 2) + '\\n'}</pre>}>\n          <Accordion.Summary>Query</Accordion.Summary>\n        </Accordion>\n      </Container>\n    </>\n  )\n}\n\nexport default Example\n";