export default "import React from 'react'\nimport {\n  Afternoon16,\n  Company16,\n  Component16,\n  Container,\n  Menu,\n  Typography,\n} from '@toptal/picasso'\nimport { SPACING_6, SPACING_4 } from '@toptal/picasso-utils'\n\nconst SlideMenu = () => (\n  <Menu>\n    <Menu.Item>Label</Menu.Item>\n    <Menu.Item\n      menu={\n        <Menu>\n          <Menu.Item>Label inner</Menu.Item>\n          <Menu.Item\n            menu={\n              <Menu>\n                <Menu.Item>Label inner</Menu.Item>\n              </Menu>\n            }\n          >\n            Label inner\n          </Menu.Item>\n        </Menu>\n      }\n    >\n      Label\n    </Menu.Item>\n  </Menu>\n)\n\nconst DrilldownMenu = () => (\n  <Menu variant='drilldown'>\n    <Menu.Item>Label</Menu.Item>\n    <Menu.Item\n      menu={\n        <Menu variant='drilldown'>\n          <Menu.Item>Label inner</Menu.Item>\n          <Menu.Item\n            menu={\n              <Menu variant='drilldown'>\n                <Menu.Item>Label inner</Menu.Item>\n              </Menu>\n            }\n          >\n            Label inner\n          </Menu.Item>\n        </Menu>\n      }\n    >\n      Label\n    </Menu.Item>\n  </Menu>\n)\n\nconst SlideMenuWithIcon = () => (\n  <Menu>\n    <Menu.Item icon={<Afternoon16 />}>Label</Menu.Item>\n    <Menu.Item\n      icon={<Company16 />}\n      menu={\n        <Menu>\n          <Menu.Item icon={<Afternoon16 />}>Label inner</Menu.Item>\n          <Menu.Item\n            icon={<Company16 />}\n            menu={\n              <Menu>\n                <Menu.Item icon={<Component16 />}>Label inner</Menu.Item>\n              </Menu>\n            }\n          >\n            Label inner\n          </Menu.Item>\n        </Menu>\n      }\n    >\n      Label\n    </Menu.Item>\n  </Menu>\n)\nconst DrilldownMenuWithDescIcon = () => (\n  <Menu variant='drilldown'>\n    <Menu.Item description='Description' icon={<Afternoon16 />}>\n      Label\n    </Menu.Item>\n    <Menu.Item\n      description='Description'\n      icon={<Company16 />}\n      menu={\n        <Menu variant='drilldown'>\n          <Menu.Item description='Description' icon={<Afternoon16 />}>\n            Label inner\n          </Menu.Item>\n          <Menu.Item\n            description='Description'\n            icon={<Company16 />}\n            menu={\n              <Menu variant='drilldown'>\n                <Menu.Item description='Description' icon={<Component16 />}>\n                  Label inner\n                </Menu.Item>\n              </Menu>\n            }\n          >\n            Label inner\n          </Menu.Item>\n        </Menu>\n      }\n    >\n      Label\n    </Menu.Item>\n  </Menu>\n)\n\nconst Example = () => {\n  return (\n    <Container flex gap={SPACING_6}>\n      <ExampleContainer title='Slide (default)'>\n        <SlideMenu />\n      </ExampleContainer>\n\n      <ExampleContainer title='Drilldown'>\n        <DrilldownMenu />\n      </ExampleContainer>\n\n      <ExampleContainer title='Slide with Icon'>\n        <SlideMenuWithIcon />\n      </ExampleContainer>\n\n      <ExampleContainer title='Drilldown with Description and Icon'>\n        <DrilldownMenuWithDescIcon />\n      </ExampleContainer>\n    </Container>\n  )\n}\n\nconst ExampleContainer = ({\n  title,\n  children,\n}: {\n  title: string\n  children: React.ReactNode\n}) => {\n  return (\n    <Container flex gap={SPACING_4} direction='column'>\n      <Typography variant='heading' size='small'>\n        {title}\n      </Typography>\n      <Container>{children}</Container>\n    </Container>\n  )\n}\n\nexport default Example\n";