export default "import React from 'react'\nimport { Grid, Container, Typography } from '@toptal/picasso'\nimport { SPACING_4, palette, useBreakpoint } from '@toptal/picasso-utils'\n\nconst ScreenSize = () => {\n  const isExtraLarge = useBreakpoint('xl')\n  const isLarge = useBreakpoint('lg')\n  const isMedium = useBreakpoint('md')\n\n  if (isExtraLarge) {\n    return <>Extra Large</>\n  }\n  if (isLarge) {\n    return <>Large</>\n  }\n  if (isMedium) {\n    return <>Medium</>\n  }\n\n  return <>Small</>\n}\n\ntype Props = { children: React.ReactNode }\n\nconst ContentContainer = ({ children }: Props) => (\n  <Container\n    padded={SPACING_4}\n    style={{ backgroundColor: palette.blue.lighter }}\n  >\n    <Typography variant='heading' size='small' align='center'>\n      {children}\n    </Typography>\n  </Container>\n)\n\nconst Example = () => {\n  return (\n    <Grid>\n      <Grid.Item sm={12} md={6} lg={3}>\n        <ContentContainer>\n          <ScreenSize />\n        </ContentContainer>\n      </Grid.Item>\n      <Grid.Item sm={12} md={6} lg={3}>\n        <ContentContainer>\n          <ScreenSize />\n        </ContentContainer>\n      </Grid.Item>\n      <Grid.Item sm={12} md={6} lg={3}>\n        <ContentContainer>\n          <ScreenSize />\n        </ContentContainer>\n      </Grid.Item>\n      <Grid.Item sm={12} md={6} lg={3}>\n        <ContentContainer>\n          <ScreenSize />\n        </ContentContainer>\n      </Grid.Item>\n    </Grid>\n  )\n}\n\nexport default Example\n";