export default "import React from 'react'\nimport {\n  Page,\n  Container,\n  Menu,\n  Typography,\n  Tooltip,\n  Button,\n  Globe16,\n  Profile16,\n  Home16,\n  HeartbeatResponsive,\n} from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\n\nconst Example = () => (\n  <div style={{ height: '30rem' }}>\n    <Page>\n      <Page.TopBar\n        rightContent={<RightContent />}\n        actionItems={<ActionItems />}\n        centerContent={<CenterContent />}\n        title='Default example'\n      />\n      <Page.Content>\n        <SidebarMenu />\n        <Page.Article>\n          <Content />\n        </Page.Article>\n      </Page.Content>\n      <Page.Footer />\n    </Page>\n  </div>\n)\n\nconst handleClick = () => window.alert('Item clicked')\n\nconst CenterContent = () => (\n  <Page.TopBar.Menu>\n    <Page.TopBar.Item>Item 1</Page.TopBar.Item>\n    <Page.TopBar.Item>Item 2</Page.TopBar.Item>\n    <Page.TopBar.Item>Item 3</Page.TopBar.Item>\n  </Page.TopBar.Menu>\n)\n\nconst SidebarMenu = () => (\n  <Page.Sidebar>\n    <Page.Sidebar.Menu>\n      <Page.Sidebar.Item selected icon={<Home16 />}>\n        Home\n      </Page.Sidebar.Item>\n      <Page.Sidebar.Item icon={<Profile16 />}>Contacts</Page.Sidebar.Item>\n      <Page.Sidebar.Item icon={<Globe16 />}>Team</Page.Sidebar.Item>\n    </Page.Sidebar.Menu>\n  </Page.Sidebar>\n)\n\nconst RightContent = () => (\n  <Page.TopBarMenu\n    name='Jacqueline Roque'\n    avatar='./jacqueline-with-flowers-1954-square.jpg'\n  >\n    <Menu>\n      <Menu.Item onClick={handleClick}>My Account</Menu.Item>\n      <Menu.Item onClick={handleClick}>Log Out</Menu.Item>\n    </Menu>\n  </Page.TopBarMenu>\n)\n\nconst ActionItems = () => (\n  <Tooltip content='Your Operational Issues'>\n    <Button.Circular\n      variant='transparent'\n      responsive\n      icon={<HeartbeatResponsive color='light-grey' />}\n      data-testid='operational-issues-button'\n      onClick={() => {}}\n    />\n  </Tooltip>\n)\n\nconst Content = () => (\n  <Container top={SPACING_4} bottom={SPACING_4}>\n    <Container bottom={SPACING_4}>\n      <Typography align='center' variant='heading' size='large'>\n        Default example\n      </Typography>\n    </Container>\n    <Typography>\n      Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod\n      tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim\n      veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea\n      commodo consequat. Duis aute irure dolor in reprehenderit in voluptate\n      velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat\n      cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id\n      est laborum.\n    </Typography>\n  </Container>\n)\n\nexport default Example\n";