export default "import React, { useState } from 'react'\nimport type { TableProps } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\nimport { Table, Select, Container } from '@toptal/picasso'\n\nconst data = [\n  {\n    id: 0,\n    name: 'Delia Floyd',\n    talentType: 'Designer',\n    company: 'Airbnb',\n    role: 'UX lead',\n    country: 'United States',\n  },\n  {\n    id: 1,\n    name: 'Linnie Sims',\n    talentType: 'Designer',\n    company: 'Facebook',\n    role: 'Art director',\n    country: 'Spain',\n  },\n  {\n    id: 2,\n    name: 'Charles Watson',\n    talentType: 'Developer',\n    company: 'Amazon',\n    role: 'Ruby developer',\n    country: 'Germany',\n  },\n  {\n    id: 3,\n    name: 'Leila Pena',\n    talentType: 'Developer',\n    company: 'Invision',\n    role: 'Web developer',\n    country: 'Poland',\n  },\n  {\n    id: 4,\n    name: 'Logan Burton',\n    talentType: 'Developer',\n    company: 'Microsoft',\n    role: 'CTO',\n    country: 'United States',\n  },\n]\n\nconst Example = () => {\n  const [spacing, setSpacing] = useState<TableProps['spacing']>('narrow')\n\n  return (\n    <>\n      <Container bottom={SPACING_4}>\n        <Select\n          onChange={event => setSpacing(event.target.value)}\n          options={[\n            { value: 'regular', text: 'Regular' },\n            { value: 'narrow', text: 'Narrow' },\n            { value: 'compact', text: 'Compact' },\n          ]}\n          value={spacing}\n          placeholder='Choose an option...'\n          width='auto'\n        />\n      </Container>\n      <Table spacing={spacing}>\n        <Table.Head>\n          <Table.Row>\n            <Table.Cell>Name</Table.Cell>\n            <Table.Cell>Talent type</Table.Cell>\n            <Table.Cell>Company</Table.Cell>\n            <Table.Cell>Role</Table.Cell>\n            <Table.Cell>Country</Table.Cell>\n          </Table.Row>\n        </Table.Head>\n        <Table.Body>\n          {data.map(row => (\n            <Table.Row key={row.id}>\n              <Table.Cell>{row.name}</Table.Cell>\n              <Table.Cell>{row.talentType}</Table.Cell>\n              <Table.Cell>{row.company}</Table.Cell>\n              <Table.Cell>{row.role}</Table.Cell>\n              <Table.Cell>{row.country}</Table.Cell>\n            </Table.Row>\n          ))}\n        </Table.Body>\n        <Table.Footer>\n          <Table.Row>\n            <Table.Cell colSpan={3}>Total</Table.Cell>\n            <Table.Cell>Role</Table.Cell>\n            <Table.Cell>Country</Table.Cell>\n          </Table.Row>\n        </Table.Footer>\n      </Table>\n    </>\n  )\n}\n\nexport default Example\n";