export default "import React from 'react'\nimport { Table } from '@toptal/picasso'\n\nconst data = [\n  {\n    id: 0,\n    name: 'Delia Floyd',\n    talentType: 'Designer',\n    company: 'Airbnb',\n    role: 'UX lead',\n    country: 'United States',\n  },\n  {\n    id: 1,\n    name: 'Linnie Sims',\n    talentType: 'Designer',\n    company: 'Facebook',\n    role: 'Art director',\n    country: 'Spain',\n  },\n  {\n    id: 2,\n    name: 'Charles Watson',\n    talentType: 'Developer',\n    company: 'Amazon',\n    role: 'Ruby developer',\n    country: 'Germany',\n  },\n  {\n    id: 3,\n    name: 'Leila Pena',\n    talentType: 'Developer',\n    company: 'Invision',\n    role: 'Web developer',\n    country: 'Poland',\n  },\n  {\n    id: 4,\n    name: 'Logan Burton',\n    talentType: 'Developer',\n    company: 'Microsoft',\n    role: 'CTO',\n    country: 'United States',\n  },\n]\n\nconst Example = () => (\n  <Table>\n    <Table.Head>\n      <Table.Row>\n        <Table.Cell>Name</Table.Cell>\n        <Table.Cell align='center'>Talent type</Table.Cell>\n        <Table.Cell align='center'>Company</Table.Cell>\n        <Table.Cell align='center'>Role</Table.Cell>\n        <Table.Cell align='right'>Country</Table.Cell>\n      </Table.Row>\n    </Table.Head>\n    <Table.Body>\n      {data.map(row => (\n        <Table.Row key={row.id}>\n          <Table.Cell>{row.name}</Table.Cell>\n          <Table.Cell align='center'>{row.talentType}</Table.Cell>\n          <Table.Cell align='center'>{row.company}</Table.Cell>\n          <Table.Cell align='center'>{row.role}</Table.Cell>\n          <Table.Cell align='right'>{row.country}</Table.Cell>\n        </Table.Row>\n      ))}\n    </Table.Body>\n    <Table.Footer>\n      <Table.Row>\n        <Table.Cell colSpan={3}>Total</Table.Cell>\n        <Table.Cell align='center'>Role</Table.Cell>\n        <Table.Cell align='right'>Country</Table.Cell>\n      </Table.Row>\n    </Table.Footer>\n  </Table>\n)\n\nexport default Example\n";