export default "import React from 'react'\nimport { BarChart } from '@toptal/picasso-charts'\nimport { palette } from '@toptal/picasso-utils'\n\nconst CHART_DATA = [\n  {\n    name: 'Training',\n    value: {\n      'q1 budget': 2000,\n      'q1 actual': 1600,\n      'q2 budget': 1672,\n      'q2 actual': 1200,\n    },\n  },\n  {\n    name: 'Events',\n    value: {\n      'q1 budget': 1752,\n      'q1 actual': 1423,\n      'q2 budget': 1856,\n      'q2 actual': 1452,\n    },\n  },\n]\n\nconst COLORS_MAPPING: Record<string, string> = {\n  'q1 budget': palette.blue.main,\n  'q1 actual': palette.grey.dark,\n  'q2 budget': palette.blue.light,\n  'q2 actual': palette.grey.light,\n}\n\nconst Example = () => (\n  <div style={{ width: 720 }}>\n    <BarChart\n      data={CHART_DATA}\n      stackedBars={[\n        ['q1 budget', 'q1 actual'],\n        ['q2 budget', 'q2 actual'],\n      ]}\n      getBarColor={({ dataKey }) => COLORS_MAPPING[dataKey]}\n      getBarLabelColor={() => palette.grey.dark}\n      width='100%'\n    />\n  </div>\n)\n\nexport default Example\n";