export default "import React from 'react'\nimport { TreeNodeAvatar, Container, Typography } from '@toptal/picasso'\nimport { SPACING_6 } from '@toptal/picasso-utils'\n\nconst Example = () => (\n  <Container>\n    <Container bottom={SPACING_6}>\n      <TreeNodeAvatar name='John Doe' size='xsmall' />\n    </Container>\n    <Container bottom={SPACING_6}>\n      <TreeNodeAvatar\n        name='John Doe'\n        src='jacqueline/128x128.jpg'\n        size='small'\n      />\n    </Container>\n    <Typography variant='heading' size='large'>\n      objectFit\n    </Typography>\n    <Typography variant='heading' size='medium'>\n      objectFit=contain (default)\n    </Typography>\n    <Container bottom={SPACING_6}>\n      <TreeNodeAvatar\n        name='John Doe'\n        src='jacqueline/128x88.jpg'\n        size='small'\n      />\n    </Container>\n    <Container bottom={SPACING_6}>\n      <TreeNodeAvatar\n        name='John Doe'\n        src='jacqueline/88x128.jpg'\n        size='small'\n      />\n    </Container>\n    <Typography variant='heading' size='medium'>\n      objectFit=cover\n    </Typography>\n    <Container bottom={SPACING_6}>\n      <TreeNodeAvatar\n        name='John Doe'\n        objectFit='cover'\n        src='jacqueline/128x88.jpg'\n        size='small'\n      />\n    </Container>\n    <Container bottom={SPACING_6}>\n      <TreeNodeAvatar\n        name='John Doe'\n        objectFit='cover'\n        src='jacqueline/88x128.jpg'\n        size='small'\n      />\n    </Container>\n  </Container>\n)\n\nexport default Example\n";