export default "import React from 'react'\nimport { Form, Grid, Input, Typography, Autocomplete } from '@toptal/picasso'\n\nconst options = [\n  { text: 'Belarus', value: 'BY' },\n  { text: 'Croatia', value: 'HR' },\n  { text: 'Lithuania', value: 'LU' },\n  { text: 'Slovakia', value: 'SK' },\n  { text: 'Ukraine', value: 'UA' },\n]\n\nconst AutofillExample = () => (\n  <Grid>\n    <Grid.Item sm={5}>\n      <Typography variant='heading'>Autofill enabled for country</Typography>\n      <Form>\n        <Form.Field>\n          <Form.Label>Address</Form.Label>\n          <Input\n            name='ship-address'\n            width='full'\n            autoComplete='shipping street-address'\n            placeholder='123 Any Street'\n          />\n        </Form.Field>\n\n        <Form.Field>\n          <Form.Label>City</Form.Label>\n          <Input\n            placeholder='New York'\n            name='ship-city'\n            autoComplete='shipping locality'\n            width='full'\n          />\n        </Form.Field>\n\n        <Form.Field>\n          <Form.Label>Zip</Form.Label>\n          <Input\n            name='ship-zip'\n            autoComplete='shipping postal-code'\n            width='full'\n            placeholder='10011'\n          />\n        </Form.Field>\n\n        <Form.Field>\n          <Form.Label>Country</Form.Label>\n          <Autocomplete\n            value=''\n            options={options}\n            width='full'\n            name='country'\n            autoComplete='shipping country-name'\n            placeholder='USA'\n            enableAutofill\n          />\n        </Form.Field>\n      </Form>\n    </Grid.Item>\n\n    <Grid.Item sm={5}>\n      <Typography variant='heading'>Autofill disabled for country</Typography>\n      <Form>\n        <Form.Field>\n          <Form.Label>Address</Form.Label>\n          <Input\n            name='ship-address'\n            width='full'\n            autoComplete='shipping street-address'\n            placeholder='123 Any Street'\n          />\n        </Form.Field>\n\n        <Form.Field>\n          <Form.Label>City</Form.Label>\n          <Input\n            placeholder='New York'\n            name='ship-city'\n            autoComplete='shipping locality'\n            width='full'\n          />\n        </Form.Field>\n\n        <Form.Field>\n          <Form.Label>Zip</Form.Label>\n          <Input\n            name='ship-zip'\n            autoComplete='shipping postal-code'\n            width='full'\n            placeholder='10011'\n          />\n        </Form.Field>\n\n        <Form.Field>\n          <Form.Label>Country</Form.Label>\n          <Autocomplete\n            value=''\n            options={options}\n            width='full'\n            name='country'\n            autoComplete='shipping country-name'\n            placeholder='USA'\n          />\n        </Form.Field>\n      </Form>\n    </Grid.Item>\n  </Grid>\n)\n\nexport default AutofillExample\n";