export default "import React from 'react'\nimport { Dropdown, Menu, Container, Typography } from '@toptal/picasso'\nimport { SPACING_2, SPACING_6, SPACING_8 } from '@toptal/picasso-utils'\n\nconst Example = () => (\n  <div>\n    <Container bottom={SPACING_2}>\n      <Typography>Popper placement</Typography>\n    </Container>\n    <Container flex inline bottom={SPACING_6}>\n      <Container right={SPACING_8}>\n        <Dropdown\n          content={\n            <Menu>\n              <Menu.Item>First item</Menu.Item>\n              <Menu.Item>Second item</Menu.Item>\n              <Menu.Item>Third item</Menu.Item>\n            </Menu>\n          }\n        >\n          Default Dropdown (bottom right)\n          <Dropdown.Arrow />\n        </Dropdown>\n      </Container>\n\n      <Container right={SPACING_8}>\n        <Dropdown\n          content={\n            <Menu>\n              <Menu.Item>First item</Menu.Item>\n              <Menu.Item>Second item</Menu.Item>\n              <Menu.Item>Third item</Menu.Item>\n            </Menu>\n          }\n          placement='top-start'\n        >\n          Top left Dropdown\n          <Dropdown.Arrow />\n        </Dropdown>\n      </Container>\n\n      <Container right={SPACING_8}>\n        <Dropdown\n          content={\n            <Menu>\n              <Menu.Item>First item</Menu.Item>\n              <Menu.Item>Second item</Menu.Item>\n              <Menu.Item>Third item</Menu.Item>\n            </Menu>\n          }\n          placement='bottom-start'\n        >\n          Bottom left Dropdown\n          <Dropdown.Arrow />\n        </Dropdown>\n      </Container>\n    </Container>\n\n    <Container bottom={SPACING_2}>\n      <Typography>Offsets</Typography>\n    </Container>\n    <Container flex inline bottom={SPACING_6}>\n      <Container right={SPACING_8}>\n        <Dropdown\n          content={\n            <Menu>\n              <Menu.Item>First item</Menu.Item>\n              <Menu.Item>Second item</Menu.Item>\n              <Menu.Item>Third item</Menu.Item>\n            </Menu>\n          }\n        >\n          Offset - default (no offset)\n          <Dropdown.Arrow />\n        </Dropdown>\n      </Container>\n\n      <Container right={SPACING_8}>\n        <Dropdown\n          content={\n            <Menu>\n              <Menu.Item>First item</Menu.Item>\n              <Menu.Item>Second item</Menu.Item>\n              <Menu.Item>Third item</Menu.Item>\n            </Menu>\n          }\n          offset={{ top: SPACING_8 }}\n        >\n          Large offset - top\n          <Dropdown.Arrow />\n        </Dropdown>\n      </Container>\n\n      <Container right={SPACING_8}>\n        <Dropdown\n          content={\n            <Menu>\n              <Menu.Item>First item</Menu.Item>\n              <Menu.Item>Second item</Menu.Item>\n              <Menu.Item>Third item</Menu.Item>\n            </Menu>\n          }\n          offset={{ right: SPACING_6 }}\n        >\n          Medium offset - right\n          <Dropdown.Arrow />\n        </Dropdown>\n      </Container>\n    </Container>\n  </div>\n)\n\nexport default Example\n";