export default "import React from 'react'\nimport {\n  Menu,\n  Container,\n  Typography,\n  Afternoon16,\n  Company16,\n  Component16,\n  Avatar,\n} from '@toptal/picasso'\nimport { SPACING_6, SPACING_4 } from '@toptal/picasso-utils'\n\nconst handleClick = () => window.alert('Item clicked')\n\nconst Example = () => (\n  <Container flex gap={SPACING_6}>\n    <Container flex gap={SPACING_4} direction='column'>\n      <Typography variant='heading' size='small'>\n        Regular\n      </Typography>\n      <Menu data-testid='menu'>\n        <Menu.Item onClick={handleClick}>Label</Menu.Item>\n        <Menu.Item disabled onClick={handleClick}>\n          Label\n        </Menu.Item>\n        <Menu.Item onClick={handleClick}>Label</Menu.Item>\n      </Menu>\n    </Container>\n\n    <Container flex gap={SPACING_4} direction='column'>\n      <Typography variant='heading' size='small'>\n        With Description\n      </Typography>\n      <Menu data-testid='menu'>\n        <Menu.Item description='Description' onClick={handleClick}>\n          Label\n        </Menu.Item>\n        <Menu.Item disabled description='Description' onClick={handleClick}>\n          Label\n        </Menu.Item>\n        <Menu.Item description='Description' onClick={handleClick}>\n          Label\n        </Menu.Item>\n      </Menu>\n    </Container>\n\n    <Container flex gap={SPACING_4} direction='column'>\n      <Typography variant='heading' size='small'>\n        With Icon\n      </Typography>\n      <Menu data-testid='menu'>\n        <Menu.Item icon={<Afternoon16 />} onClick={handleClick}>\n          Label\n        </Menu.Item>\n        <Menu.Item disabled icon={<Company16 />} onClick={handleClick}>\n          Label\n        </Menu.Item>\n        <Menu.Item icon={<Component16 />} onClick={handleClick}>\n          Label\n        </Menu.Item>\n      </Menu>\n    </Container>\n\n    <Container flex gap={SPACING_4} direction='column'>\n      <Typography variant='heading' size='small'>\n        With Description and Icon\n      </Typography>\n      <Menu data-testid='menu'>\n        <Menu.Item\n          description='Description'\n          icon={<Afternoon16 />}\n          onClick={handleClick}\n        >\n          Label\n        </Menu.Item>\n        <Menu.Item\n          disabled\n          description='Description'\n          icon={<Company16 />}\n          onClick={handleClick}\n        >\n          Label\n        </Menu.Item>\n        <Menu.Item\n          description='Description'\n          icon={<Component16 />}\n          onClick={handleClick}\n        >\n          Label\n        </Menu.Item>\n      </Menu>\n    </Container>\n\n    <Container flex gap={SPACING_4} direction='column'>\n      <Typography variant='heading' size='small'>\n        With avatar\n      </Typography>\n      <Menu data-testid='menu'>\n        <Menu.Item\n          description='Description'\n          avatar={\n            <Avatar\n              alt='Jacqueline Roque. Pablo Picasso, 1954'\n              src='./jacqueline-with-flowers-1954-square.jpg'\n              name='Jacqueline Roque'\n            />\n          }\n          onClick={handleClick}\n        >\n          Label\n        </Menu.Item>\n        <Menu.Item\n          disabled\n          avatar={\n            <Avatar\n              alt='Jacqueline Roque. Pablo Picasso, 1954'\n              src='./jacqueline-with-flowers-1954-square.jpg'\n              name='Jacqueline Roque'\n            />\n          }\n          description='Description'\n          onClick={handleClick}\n        >\n          Label\n        </Menu.Item>\n        <Menu.Item\n          description='Description'\n          avatar={\n            <Avatar\n              alt='Jacqueline Roque. Pablo Picasso, 1954'\n              src='./jacqueline-with-flowers-1954-square.jpg'\n              name='Jacqueline Roque'\n            />\n          }\n          onClick={handleClick}\n        >\n          Label\n        </Menu.Item>\n      </Menu>\n    </Container>\n  </Container>\n)\n\nexport default Example\n";