export default "import React, { useState } from 'react'\nimport { Button, Grid, Slider } from '@toptal/picasso'\nimport { Plus16, Minus16 } from '@toptal/picasso-icons'\n\ntype Value = number | number[]\n\nconst Example = () => {\n  const [value, setValue] = useState(0)\n  const handleChange = (_: React.ChangeEvent<{}>, newValue: Value) => {\n    setValue(Number(newValue))\n  }\n\n  return (\n    <Grid alignItems='center'>\n      <Grid.Item sm={6}>\n        <Grid alignItems='center'>\n          <Grid.Item>\n            <Button\n              onClick={() => setValue(value - 1)}\n              variant='secondary'\n              size='small'\n              icon={<Minus16 />}\n            >\n              Zoom out\n            </Button>\n          </Grid.Item>\n          <Grid.Item sm>\n            <Slider value={value} onChange={handleChange} max={5} />\n          </Grid.Item>\n          <Grid.Item>\n            <Button\n              onClick={() => setValue(value + 1)}\n              variant='secondary'\n              size='small'\n              icon={<Plus16 />}\n            >\n              Zoom In\n            </Button>\n          </Grid.Item>\n        </Grid>\n      </Grid.Item>\n    </Grid>\n  )\n}\n\nexport default Example\n";