export default "import React from 'react'\nimport { Container, Grid, Typography } from '@toptal/picasso'\n\nconst LargeContent = () => {\n  return (\n    <>\n      <Container variant='red' padded='xlarge'>\n        1\n      </Container>\n      <Container variant='red' padded='xlarge'>\n        2\n      </Container>\n      <Container variant='red' padded='xlarge'>\n        3\n      </Container>\n      <Container variant='red' padded='xlarge'>\n        4\n      </Container>\n      <Container variant='red' padded='xlarge'>\n        5\n      </Container>\n      <Container variant='red' padded='xlarge'>\n        6\n      </Container>\n      <Container variant='red' padded='xlarge'>\n        7\n      </Container>\n    </>\n  )\n}\n\nconst Example = () => (\n  <Grid>\n    <Grid.Item sm={6} style={{ overflow: 'hidden' }}>\n      <Typography variant='heading' size='medium'>\n        Default (nowrap)\n      </Typography>\n\n      <Container top='small' flex gap='xlarge'>\n        <LargeContent />\n      </Container>\n    </Grid.Item>\n    <Grid.Item sm={6} style={{ overflow: 'hidden' }}>\n      <Typography variant='heading' size='medium'>\n        Explicit nowrap\n      </Typography>\n\n      <Container top='small' flex gap='xlarge' wrap='nowrap'>\n        <LargeContent />\n      </Container>\n    </Grid.Item>\n    <Grid.Item sm={6}>\n      <Typography variant='heading' size='medium'>\n        Wrap\n      </Typography>\n      <Container top='small' flex gap='xlarge' wrap='wrap'>\n        <LargeContent />\n      </Container>\n    </Grid.Item>\n    <Grid.Item sm={6}>\n      <Typography variant='heading' size='medium'>\n        Wrap (reverse)\n      </Typography>\n\n      <Container top='small' flex gap='xlarge' wrap='wrap-reverse'>\n        <LargeContent />\n      </Container>\n    </Grid.Item>\n  </Grid>\n)\n\nexport default Example\n";