export default "import type { ChangeEvent } from 'react'\nimport React, { useState, useCallback } from 'react'\nimport type { SelectOption } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\nimport { Select, Container, Typography } from '@toptal/picasso'\n\nconst FilterOptionsExample = () => {\n  const [value, setValue] = useState<string>('')\n  const [values, setValues] = useState<string[]>([])\n\n  const handleChange = (\n    event: ChangeEvent<{\n      name?: string\n      value: string\n    }>\n  ) => {\n    setValue(event.target.value)\n  }\n\n  const handleMultipleChange = (\n    event: React.ChangeEvent<{ value: string[] }>\n  ) => {\n    setValues(event.target.value)\n  }\n\n  const filterOptions = useCallback(\n    (options: SelectOption[], searchValue: string) => {\n      // custom filtering logic (e.g. filtering by the last word)\n      const filteredOptions = options.filter(option =>\n        option.text.toLowerCase().endsWith(searchValue.toLowerCase())\n      )\n\n      return filteredOptions\n    },\n    []\n  )\n\n  return (\n    <Container flex inline>\n      <Container right={SPACING_4}>\n        <Typography variant='heading' size='small'>\n          Non grouped\n        </Typography>\n        <Select\n          onChange={handleChange}\n          value={value}\n          options={OPTIONS}\n          placeholder='Choose an option...'\n          width='auto'\n          data-testid='select'\n          searchThreshold={4}\n          filterOptions={filterOptions}\n        />\n      </Container>\n      <Container right={SPACING_4}>\n        <Typography variant='heading' size='small'>\n          Grouped\n        </Typography>\n        <Select\n          onChange={handleMultipleChange}\n          options={OPTION_GROUPS}\n          value={values}\n          placeholder='Choose an option...'\n          width='auto'\n          searchThreshold={4}\n          filterOptions={filterOptions}\n          multiple\n        />\n      </Container>\n    </Container>\n  )\n}\n\nconst OPTIONS = [\n  { text: 'Belarus', value: 'BY' },\n  { text: 'Croatia', value: 'HR' },\n  { text: 'Lithuania', value: 'LU' },\n  { text: 'Slovakia', value: 'SK' },\n  { text: 'Ukraine', value: 'UA' },\n  { text: 'Romania', value: 'RO' },\n]\n\nconst OPTION_GROUPS = {\n  'Group 1': [\n    { text: 'Belarus', value: 'BY' },\n    { text: 'Croatia', value: 'HR' },\n  ],\n  'Group 2': [\n    { text: 'Lithuania', value: 'LU' },\n    { text: 'Slovakia', value: 'SK' },\n  ],\n  'Group 3': [\n    { text: 'Ukraine', value: 'UA' },\n    { text: 'Romania', value: 'RO' },\n  ],\n}\n\nexport default FilterOptionsExample\n";