export default "import React from 'react'\nimport { Indicator, Typography, Container } from '@toptal/picasso'\nimport { SPACING_6, SPACING_4 } from '@toptal/picasso-utils'\n\nconst Example = () => (\n  <>\n    <Container bottom={SPACING_6}>\n      <Container inline right={SPACING_4}>\n        <Indicator color='light-blue' />\n      </Container>\n      <Typography inline size='medium'>\n        Light blue\n      </Typography>\n    </Container>\n\n    <Container bottom={SPACING_6}>\n      <Container bottom={SPACING_6}>\n        <Container inline right={SPACING_4}>\n          <Indicator color='light-grey' />\n        </Container>\n        <Typography inline size='medium'>\n          Pending item\n        </Typography>\n      </Container>\n\n      <Container inline right={SPACING_4}>\n        <Indicator color='green' />\n      </Container>\n      <Typography inline size='medium'>\n        Completed item\n      </Typography>\n    </Container>\n\n    <Container bottom={SPACING_6}>\n      <Container inline right={SPACING_4}>\n        <Indicator color='red' />\n      </Container>\n      <Typography inline size='medium'>\n        High priority\n      </Typography>\n    </Container>\n\n    <Container bottom={SPACING_6}>\n      <Container inline right={SPACING_4}>\n        <Indicator color='yellow' />\n      </Container>\n      <Typography inline size='medium'>\n        Medium priority\n      </Typography>\n    </Container>\n\n    <Container inline right={SPACING_4}>\n      <Indicator color='blue' />\n    </Container>\n    <Typography inline size='medium'>\n      Low priority\n    </Typography>\n  </>\n)\n\nexport default Example\n";