export default "import React from 'react'\nimport { Grid, Button, Container, Typography } from '@toptal/picasso'\nimport { SPACING_8, SPACING_4 } from '@toptal/picasso-utils'\n\nconst Example = () => (\n  <div>\n    <Container bottom={SPACING_8}>\n      <Container bottom={SPACING_4}>\n        <Typography>Wrap</Typography>\n      </Container>\n      <Grid wrap='wrap' style={{ maxWidth: '200px' }}>\n        <Grid.Item>\n          <Button>1</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>2</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>3</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>4</Button>\n        </Grid.Item>\n      </Grid>\n    </Container>\n\n    <Container bottom={SPACING_8}>\n      <Container bottom={SPACING_4}>\n        <Typography>Nowrap</Typography>\n      </Container>\n      <Grid wrap='nowrap' style={{ maxWidth: '200px' }}>\n        <Grid.Item>\n          <Button>1</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>2</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>3</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>4</Button>\n        </Grid.Item>\n      </Grid>\n    </Container>\n\n    <Container bottom={SPACING_8}>\n      <Container bottom={SPACING_4}>\n        <Typography>Wrap-reverse</Typography>\n      </Container>\n      <Grid wrap='wrap-reverse' style={{ maxWidth: '200px' }}>\n        <Grid.Item>\n          <Button>1</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>2</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>3</Button>\n        </Grid.Item>\n        <Grid.Item>\n          <Button>4</Button>\n        </Grid.Item>\n      </Grid>\n    </Container>\n  </div>\n)\n\nexport default Example\n";