export default "import React, { useEffect, useState } from 'react'\nimport {\n  QueryBuilder,\n  type RuleGroupTypeAny,\n} from '@toptal/picasso-query-builder'\n\ntype MultiSelectOptions = {\n  label: string\n  name: string\n}\n\nconst defaultQuery = {\n  rules: [],\n  combinator: 'and',\n}\n\nconst multiselectOptions = [\n  {\n    label: 'Digital Design',\n    name: 'DIGITAL_DESIGN',\n  },\n  {\n    label: 'UI',\n    name: 'UI',\n  },\n  {\n    label: 'Salesforce',\n    name: 'SALESFORCE',\n  },\n]\n\nconst Example = () => {\n  const [query, setQuery] = useState<RuleGroupTypeAny>(defaultQuery)\n  const [loading, setLoading] = useState<boolean>(false)\n  const [options, setOptions] = useState<MultiSelectOptions[]>()\n\n  useEffect(() => {\n    const loadOptions = async () => {\n      setLoading(true)\n      const data = await new Promise<MultiSelectOptions[]>(resolve =>\n        setTimeout(() => {\n          resolve(multiselectOptions)\n          setLoading(false)\n        }, 1000)\n      )\n\n      setOptions(data)\n    }\n\n    loadOptions()\n  }, [])\n\n  const fields = [\n    {\n      name: 'Multiselect',\n      label: 'Multiselect',\n      valueEditorType: 'multiselect' as const,\n      values: options,\n      loading: loading,\n    },\n  ]\n\n  const handleChange = (newQuery: RuleGroupTypeAny) => {\n    setQuery(newQuery)\n  }\n\n  return (\n    <QueryBuilder fields={fields} query={query} onQueryChange={handleChange} />\n  )\n}\n\nexport default Example\n";