export default "import React, { useState } from 'react'\nimport { Dropzone } from '@toptal/picasso'\n\nconst value = [\n  {\n    uploading: false,\n    progress: 0,\n    file: new File(['resume.pdf'], 'resume.pdf'),\n  },\n]\n\nconst Example = () => {\n  const [files, setFiles] = useState(value)\n\n  const addFile = (acceptedFiles: File[]) => {\n    const newFiles = acceptedFiles.map(file => ({\n      file,\n      uploading: false,\n      progress: 0,\n    }))\n\n    setFiles(newFiles)\n  }\n\n  const handleRemove = () => {\n    setFiles([])\n  }\n\n  return (\n    <Dropzone\n      multiple={false}\n      value={files}\n      onDrop={addFile}\n      onRemove={handleRemove}\n      accept={{\n        'image/*': [],\n      }}\n    />\n  )\n}\n\nexport default Example\n";