export default "import React, { useState } from 'react'\nimport { Table, Checkbox } from '@toptal/picasso'\n\nconst data = [\n  {\n    id: 0,\n    name: 'Delia Floyd',\n    talentType: 'Designer',\n    company: 'Airbnb',\n    role: 'UX lead',\n    country: 'United States',\n  },\n  {\n    id: 1,\n    name: 'Linnie Sims',\n    talentType: 'Designer',\n    company: 'Facebook',\n    role: 'Art director',\n    country: 'Spain',\n  },\n  {\n    id: 2,\n    name: 'Charles Watson',\n    talentType: 'Developer',\n    company: 'Amazon',\n    role: 'Ruby developer',\n    country: 'Germany',\n  },\n  {\n    id: 3,\n    name: 'Leila Pena',\n    talentType: 'Developer',\n    company: 'Invision',\n    role: 'Web developer',\n    country: 'Poland',\n  },\n  {\n    id: 4,\n    name: 'Logan Burton',\n    talentType: 'Developer',\n    company: 'Microsoft',\n    role: 'CTO',\n    country: 'United States',\n  },\n]\n\nconst Example = () => {\n  const [selected, setSelected] = useState<number[]>([])\n\n  const handleClick = (_: React.ChangeEvent<{}>, id: number) => {\n    let newSelected = []\n\n    if (selected.includes(id)) {\n      newSelected = selected.filter(item => item !== id)\n    } else {\n      newSelected = [...selected, id]\n    }\n\n    setSelected(newSelected)\n  }\n\n  return (\n    <Table>\n      <Table.Head>\n        <Table.Row>\n          <Table.Cell />\n          <Table.Cell>Name</Table.Cell>\n          <Table.Cell>Talent type</Table.Cell>\n          <Table.Cell>Company</Table.Cell>\n          <Table.Cell>Role</Table.Cell>\n          <Table.Cell>Country</Table.Cell>\n        </Table.Row>\n      </Table.Head>\n      <Table.Body>\n        {data.map(({ id, name, talentType, company, role, country }) => {\n          const isSelected = selected.includes(id)\n\n          return (\n            <Table.Row\n              key={id}\n              hover\n              selected={isSelected}\n              onClick={event => handleClick(event, id)}\n            >\n              <Table.Cell>\n                <Checkbox checked={isSelected} />\n              </Table.Cell>\n              <Table.Cell>{name}</Table.Cell>\n              <Table.Cell>{talentType}</Table.Cell>\n              <Table.Cell>{company}</Table.Cell>\n              <Table.Cell>{role}</Table.Cell>\n              <Table.Cell>{country}</Table.Cell>\n            </Table.Row>\n          )\n        })}\n      </Table.Body>\n    </Table>\n  )\n}\n\nexport default Example\n";