export default "import React from 'react'\nimport { Container, EnvironmentBanner, Typography } from '@toptal/picasso'\n\nconst CONTAINER_HEIGHT = '2rem'\n\nconst Example = () => (\n  <div>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <Typography variant='heading' size='small'>\n        Development\n      </Typography>\n    </Container>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <EnvironmentBanner\n        environment='development'\n        productName='Picasso'\n        style={{ width: '100%' }}\n      />\n    </Container>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <Typography variant='heading' size='small'>\n        Temploy\n      </Typography>\n    </Container>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <EnvironmentBanner\n        environment='temploy'\n        productName='Picasso'\n        style={{ width: '100%' }}\n      />\n    </Container>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <Typography variant='heading' size='small'>\n        Staging\n      </Typography>\n    </Container>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <EnvironmentBanner\n        environment='staging'\n        productName='Picasso'\n        style={{ width: '100%' }}\n      />\n    </Container>\n    <Container style={{ position: 'relative', height: CONTAINER_HEIGHT }}>\n      <Typography variant='heading' size='small'>\n        Production (should be empty)\n      </Typography>\n    </Container>\n  </div>\n)\n\nexport default Example\n";