export default "/* eslint-disable id-length */\nimport React, { useMemo } from 'react'\nimport { Table, TableSortableCell } from '@toptal/picasso'\n\nconst data = [\n  {\n    id: 0,\n    name: 'Delia Floyd',\n    talentType: 'Designer',\n    company: 'Airbnb',\n  },\n  {\n    id: 1,\n    name: 'Linnie Sims',\n    talentType: 'Designer',\n    company: 'Facebook',\n  },\n  {\n    id: 2,\n    name: 'Charles Watson',\n    talentType: 'Developer',\n    company: 'Amazon',\n  },\n  {\n    id: 3,\n    name: 'Leila Pena',\n    talentType: 'Developer',\n    company: 'Invision',\n  },\n  {\n    id: 4,\n    name: 'Logan Burton',\n    talentType: 'Developer',\n    company: 'Microsoft',\n  },\n]\n\nconst sortAlphabetically = (\n  a: string,\n  b: string,\n  direction: 'asc' | 'desc'\n) => {\n  if (direction === 'asc') {\n    return a.localeCompare(b)\n  }\n\n  return b.localeCompare(a)\n}\n\nconst Example = () => {\n  const [sortState, setSortState] = React.useState<{\n    key: 'name' | 'talentType'\n    direction: 'asc' | 'desc'\n  }>({\n    key: 'name',\n    direction: 'asc',\n  })\n\n  const sortedData = useMemo(() => {\n    return data.sort((a, b) => {\n      return sortAlphabetically(\n        a[sortState.key],\n        b[sortState.key],\n        sortState.direction\n      )\n    })\n  }, [sortState])\n\n  const onSort = (key: 'name' | 'talentType') => {\n    setSortState({\n      key,\n      direction:\n        sortState.key === key && sortState.direction === 'asc' ? 'desc' : 'asc',\n    })\n  }\n\n  return (\n    <div>\n      <Table>\n        <Table.Head>\n          <Table.Row>\n            <TableSortableCell\n              onSortClick={() => onSort('name')}\n              sortDirection={\n                sortState.key === 'name' && sortState.direction === 'desc'\n                  ? 'desc'\n                  : 'asc'\n              }\n            >\n              Name\n            </TableSortableCell>\n            <TableSortableCell\n              onSortClick={() => onSort('talentType')}\n              sortDirection={\n                sortState.key === 'talentType' && sortState.direction === 'desc'\n                  ? 'desc'\n                  : 'asc'\n              }\n            >\n              Talent type\n            </TableSortableCell>\n            <Table.Cell>Company</Table.Cell>\n          </Table.Row>\n        </Table.Head>\n        <Table.Body>\n          {sortedData.map(row => (\n            <Table.Row key={row.id}>\n              <Table.Cell>{row.name}</Table.Cell>\n              <Table.Cell>{row.talentType}</Table.Cell>\n              <Table.Cell>{row.company}</Table.Cell>\n            </Table.Row>\n          ))}\n        </Table.Body>\n      </Table>\n    </div>\n  )\n}\n\nexport default Example\n";