export default "import type { ReactNode } from 'react'\nimport React from 'react'\nimport { PicassoLight, SPACING_12 } from '@toptal/picasso-provider'\nimport { Page, Container } from '@toptal/picasso'\n\nconst App = ({ children }: { children: ReactNode }) => (\n  <PicassoLight>\n    <Page>\n      <Page.TopBar title='Picasso without any dependencies' />\n      <Page.Content>\n        <Page.Article>\n          <Container\n            flex\n            justifyContent='center'\n            top={SPACING_12}\n            style={{ height: '14rem' }}\n          >\n            {children}\n          </Container>\n        </Page.Article>\n      </Page.Content>\n      <Page.Footer />\n    </Page>\n  </PicassoLight>\n)\n\nconst Index = () => (\n  <div id='root'>\n    <App>Your application without adding any utility components</App>\n  </div>\n)\n\nexport default Index\n";