export default "import React from 'react'\nimport { BarChart } from '@toptal/picasso-charts'\nimport { palette } from '@toptal/picasso-utils'\n\nconst CHART_DATA = [\n  {\n    name: 'Jan',\n    value: { amount: 1000 },\n  },\n  {\n    name: 'Feb',\n    value: { amount: 2000 },\n  },\n  {\n    name: 'Mar',\n    value: { amount: 5000 },\n  },\n  {\n    name: 'Apr',\n    value: { amount: 10000 },\n  },\n  {\n    name: 'May',\n    value: { amount: 9000 },\n  },\n  {\n    name: 'Jun',\n    value: { amount: 3000 },\n  },\n  {\n    name: 'Jul',\n    value: { amount: 1000 },\n  },\n]\n\nconst COLORS_MAPPING: Record<string, string> = {\n  amount: palette.green.dark,\n}\n\nconst valueAxisFormatter = (value: number) => {\n  return `$${value / 1000}k`\n}\n\nconst Example = () => (\n  <div style={{ width: 720 }}>\n    <BarChart\n      data={CHART_DATA}\n      width='100%'\n      height={300}\n      getBarColor={({ dataKey }) => COLORS_MAPPING[dataKey]}\n      getBarLabelColor={({ dataKey }) => COLORS_MAPPING[dataKey]}\n      valueAxisTickFormatter={valueAxisFormatter}\n    />\n  </div>\n)\n\nexport default Example\n";