export default "import React from 'react'\nimport {\n  Table,\n  Button,\n  Grid,\n  Typography,\n  Section,\n  Container,\n} from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\n\nconst Example = () => {\n  const content = (\n    <Table>\n      <Table.Head>\n        <Table.Row>\n          <Table.Cell>Name</Table.Cell>\n          <Table.Cell>Talent type</Table.Cell>\n          <Table.Cell>Company</Table.Cell>\n          <Table.Cell>Role</Table.Cell>\n          <Table.Cell>Country</Table.Cell>\n        </Table.Row>\n      </Table.Head>\n      <Table.Body>\n        {data.map(row => (\n          <Table.Row key={row.id}>\n            <Table.Cell>{row.name}</Table.Cell>\n            <Table.Cell>{row.talentType}</Table.Cell>\n            <Table.Cell>{row.company}</Table.Cell>\n            <Table.Cell>{row.role}</Table.Cell>\n            <Table.Cell>{row.country}</Table.Cell>\n          </Table.Row>\n        ))}\n      </Table.Body>\n    </Table>\n  )\n\n  return (\n    <Grid>\n      <Grid.Item sm={6}>\n        <Typography>Collapsible section is collapsed by default.</Typography>\n        <Section\n          title='Talents'\n          subtitle={`${data.length} people`}\n          actions={\n            <Button size='small' variant='secondary'>\n              More\n            </Button>\n          }\n          collapsible\n        >\n          {content}\n        </Section>\n      </Grid.Item>\n      <Grid.Item sm={6}>\n        <Typography>\n          You can modify this behavior with `defaultCollapsed` property.\n        </Typography>\n        <Section\n          title='Talents'\n          subtitle={`${data.length} people`}\n          actions={\n            <Button size='small' variant='secondary'>\n              More\n            </Button>\n          }\n          collapsible\n          defaultCollapsed={false}\n        >\n          {content}\n        </Section>\n      </Grid.Item>\n\n      <Grid.Item sm={6}>\n        <Typography>Collapsible section with header bar.</Typography>\n        <Container top={SPACING_4}>\n          <Section title='Details' collapsible variant='withHeaderBar'>\n            Lorem, ipsum dolor sit amet consectetur adipisicing elit. Sint\n            dolore, et ipsum eligendi sunt maiores aliquam blanditiis labore\n            praesentium magnam necessitatibus. Quisquam ipsum, doloremque sit\n            laudantium beatae nihil similique. Laborum eum itaque recusandae ut\n            eaque vero et atque dolor nostrum nobis maxime, nihil nisi non\n            perferendis amet voluptatibus odio laudantium!\n          </Section>\n        </Container>\n      </Grid.Item>\n\n      <Grid.Item sm={6}>\n        <Typography>Collapsible bordered section.</Typography>\n        <Container top={SPACING_4}>\n          <Section title='Details' collapsible variant='bordered'>\n            Lorem, ipsum dolor sit amet consectetur adipisicing elit. Sint\n            dolore, et ipsum eligendi sunt maiores aliquam blanditiis labore\n            praesentium magnam necessitatibus. Quisquam ipsum, doloremque sit\n            laudantium beatae nihil similique. Laborum eum itaque recusandae ut\n            eaque vero et atque dolor nostrum nobis maxime, nihil nisi non\n            perferendis amet voluptatibus odio laudantium!\n          </Section>\n        </Container>\n      </Grid.Item>\n    </Grid>\n  )\n}\n\nconst data = [\n  {\n    id: 0,\n    name: 'Delia Floyd',\n    talentType: 'Designer',\n    company: 'Airbnb',\n    role: 'UX lead',\n    country: 'United States',\n  },\n  {\n    id: 1,\n    name: 'Linnie Sims',\n    talentType: 'Designer',\n    company: 'Facebook',\n    role: 'Art director',\n    country: 'Spain',\n  },\n  {\n    id: 2,\n    name: 'Charles Watson',\n    talentType: 'Developer',\n    company: 'Amazon',\n    role: 'Ruby developer',\n    country: 'Germany',\n  },\n  {\n    id: 3,\n    name: 'Leila Pena',\n    talentType: 'Developer',\n    company: 'Invision',\n    role: 'Web developer',\n    country: 'Poland',\n  },\n  {\n    id: 4,\n    name: 'Logan Burton',\n    talentType: 'Developer',\n    company: 'Microsoft',\n    role: 'CTO',\n    country: 'United States',\n  },\n]\n\nexport default Example\n";