export default "import React, { useState } from 'react'\nimport { Container, Select, Typography } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\n\nconst OPTION_GROUPS = {\n  'Group 1': [\n    { value: '1', text: 'Option 1' },\n    { value: '2', text: 'Option 2' },\n  ],\n  'Group 2': [\n    { value: '3', text: 'Option 3' },\n    { value: '4', text: 'Option 4' },\n    { value: '5', text: 'Option 5' },\n  ],\n  'Group 3': [\n    { value: '6', text: 'Option 6' },\n    { value: '7', text: 'Option 7' },\n  ],\n  'Group 4': [\n    { value: '8', text: 'Option 8' },\n    { value: '9', text: 'Option 9' },\n    { value: '10', text: 'Option 10' },\n  ],\n}\n\nconst Example = () => {\n  const [value, setValue] = useState<string>()\n  const [values, setValues] = useState<string[]>([])\n\n  const handleChange = (event: React.ChangeEvent<{ value: string }>) => {\n    setValue(event.target.value)\n  }\n  const handleMultipleChange = (\n    event: React.ChangeEvent<{ value: string[] }>\n  ) => {\n    setValues(event.target.value)\n  }\n\n  return (\n    <Container flex inline>\n      <Container right={SPACING_4}>\n        <Typography variant='heading' size='small'>\n          Native\n        </Typography>\n        <Select\n          onChange={handleChange}\n          options={OPTION_GROUPS}\n          value={value}\n          placeholder='Choose an option...'\n          width='auto'\n          native\n        />\n      </Container>\n      <Container right={SPACING_4}>\n        <Typography variant='heading' size='small'>\n          Non native\n        </Typography>\n        <Select\n          onChange={handleMultipleChange}\n          options={OPTION_GROUPS}\n          value={values}\n          placeholder='Choose an option...'\n          width='auto'\n          searchThreshold={2}\n          multiple\n        />\n      </Container>\n    </Container>\n  )\n}\n\nexport default Example\n";