export default "import React from 'react'\nimport { Container, Table, Typography, Section } from '@toptal/picasso'\nimport { SPACING_4, SPACING_8 } from '@toptal/picasso-utils'\n\nconst TableDemo = () => (\n  <Table>\n    <Table.Head>\n      <Table.Row>\n        <Table.Cell>Name</Table.Cell>\n        <Table.Cell>Talent type</Table.Cell>\n        <Table.Cell>Company</Table.Cell>\n        <Table.Cell>Role</Table.Cell>\n        <Table.Cell>Country</Table.Cell>\n      </Table.Row>\n    </Table.Head>\n    <Table.Body>\n      {data.map(row => (\n        <Table.Row key={row.id}>\n          <Table.Cell>{row.name}</Table.Cell>\n          <Table.Cell>{row.talentType}</Table.Cell>\n          <Table.Cell>{row.company}</Table.Cell>\n          <Table.Cell>{row.role}</Table.Cell>\n          <Table.Cell>{row.country}</Table.Cell>\n        </Table.Row>\n      ))}\n    </Table.Body>\n  </Table>\n)\n\nconst Example = () => {\n  return (\n    <>\n      <Container>\n        <Typography variant='heading' size='small'>\n          Bordered\n        </Typography>\n        <Container top={SPACING_4}>\n          <Section\n            title='Talents'\n            subtitle={`${data.length} people`}\n            variant='bordered'\n          >\n            <TableDemo />\n          </Section>\n        </Container>\n      </Container>\n      <Container top={SPACING_8}>\n        <Typography variant='heading' size='small'>\n          WithHeaderBar\n        </Typography>\n        <Container top={SPACING_4}>\n          <Section\n            title='Talents'\n            subtitle={`${data.length} people`}\n            variant='withHeaderBar'\n          >\n            <TableDemo />\n          </Section>\n        </Container>\n      </Container>\n    </>\n  )\n}\n\nconst data = [\n  {\n    id: 0,\n    name: 'Delia Floyd',\n    talentType: 'Designer',\n    company: 'Airbnb',\n    role: 'UX lead',\n    country: 'United States',\n  },\n  {\n    id: 1,\n    name: 'Linnie Sims',\n    talentType: 'Designer',\n    company: 'Facebook',\n    role: 'Art director',\n    country: 'Spain',\n  },\n  {\n    id: 2,\n    name: 'Charles Watson',\n    talentType: 'Developer',\n    company: 'Amazon',\n    role: 'Ruby developer',\n    country: 'Germany',\n  },\n  {\n    id: 3,\n    name: 'Leila Pena',\n    talentType: 'Developer',\n    company: 'Invision',\n    role: 'Web developer',\n    country: 'Poland',\n  },\n  {\n    id: 4,\n    name: 'Logan Burton',\n    talentType: 'Developer',\n    company: 'Microsoft',\n    role: 'CTO',\n    country: 'United States',\n  },\n]\n\nexport default Example\n";