export default "import React from 'react'\nimport { Link } from '@toptal/picasso'\nimport {\n  BrowserRouter as Router,\n  Link as RouterLink,\n  Route,\n  Switch,\n} from 'react-router-dom'\n\nconst Index = () => {\n  return <h2>Home</h2>\n}\n\nconst About = () => {\n  return <h2>About</h2>\n}\n\nconst Users = () => {\n  return <h2>Users</h2>\n}\n\nconst RoutingExample = () => (\n  <Router>\n    <div>\n      <nav>\n        <ul>\n          <li>\n            <Link as={RouterLink} to='/'>\n              Home\n            </Link>\n          </li>\n          <li>\n            <Link as={RouterLink} to='/about/'>\n              About\n            </Link>\n          </li>\n          <li>\n            <Link as={RouterLink} to='/users/'>\n              Users\n            </Link>\n          </li>\n        </ul>\n      </nav>\n\n      <Switch>\n        <Route path='/about'>\n          <About />\n        </Route>\n        <Route path='/users'>\n          <Users />\n        </Route>\n        <Route>\n          <Index />\n        </Route>\n      </Switch>\n    </div>\n  </Router>\n)\n\nexport default RoutingExample\n";