export default "import React from 'react'\nimport { Pagination } from '@toptal/picasso'\n\nconst Example = () => (\n  <div>\n    <Pagination\n      activePage={4}\n      onPageChange={handlePageChange}\n      totalPages={10}\n    />\n  </div>\n)\n\nconst handlePageChange = (page: number) => {\n  window.alert('Page changed to ' + page)\n}\n\nexport default Example\n";