export default "import React, { useState } from 'react'\nimport { Select, Container, Form } from '@toptal/picasso'\nimport { SPACING_4 } from '@toptal/picasso-utils'\n\nconst Example = () => {\n  const [value, setValue] = useState<string>('')\n\n  const handleChange = (event: React.ChangeEvent<{ value: string }>) => {\n    setValue(event.target.value)\n  }\n\n  return (\n    <Container flex gap={SPACING_4}>\n      <Container>\n        <Form.Field>\n          <Form.Label>Select is disabled</Form.Label>\n          <Select\n            disabled\n            onChange={handleChange}\n            options={OPTIONS}\n            value={value}\n            placeholder='Choose an option...'\n            width='auto'\n          />\n        </Form.Field>\n      </Container>\n      <Container>\n        <Form.Field>\n          <Form.Label>Options are disabled</Form.Label>\n          <Select\n            onChange={handleChange}\n            options={OPTIONS.map((option, index) => ({\n              ...option,\n              disabled: index % 2 === 0,\n            }))}\n            value={value}\n            placeholder='Choose an option...'\n            width='auto'\n          />\n        </Form.Field>\n      </Container>\n      <Container>\n        <Form.Field>\n          <Form.Label>Native options are disabled</Form.Label>\n          <Select\n            onChange={handleChange}\n            options={OPTIONS.map((option, index) => ({\n              ...option,\n              disabled: index % 2 !== 0,\n            }))}\n            value={value}\n            placeholder='Choose an option...'\n            width='auto'\n            native\n          />\n        </Form.Field>\n      </Container>\n    </Container>\n  )\n}\n\nconst OPTIONS = [\n  { value: '1', text: 'Option 1' },\n  { value: '2', text: 'Option 2' },\n  { value: '3', text: 'Option 3' },\n  { value: '4', text: 'Option 4' },\n]\n\nexport default Example\n";